        { name: 'SLM', type: 'VOR', location: { lat: 19.7544, lon: -99.0183 }, isEntry: true }, // Santa Lucia
        { name: 'TLC', type: 'VOR', location: { lat: 19.2880, lon: -99.5670 }, isEntry: false }, // Toluca
