// Offline Response Generator
const generateOfflinePilotResponse = (text: string, aircraft: Aircraft, airport: Airport | null): { updates: Partial<Aircraft>, response: string } => {
    const t = text.toLowerCase();
    const updates: Partial<Aircraft> = {};
    const parts = [];

    // Parse Heading
    // Supports: "rumbo 120", "rumba 120"
    const hdgMatch = t.match(/rumb[oa]\s+(\d+)/);
    if (hdgMatch) {
        const val = parseInt(hdgMatch[1]);
        updates.targetHeading = val;
        parts.push(`virando rumbo ${val}`);
        updates.clearedForILS = false;
        updates.establishedOnILS = false;
        updates.currentDirectTo = null;
    }

    // Parse Direct To
    const directMatch = t.match(/directo a ([a-zA-Z0-9]+)/);
    if (directMatch) {
        const wpName = directMatch[1];
        let foundWp: Waypoint | undefined;

        if (airport) {
            foundWp = airport.waypoints.find(w => w.name.toLowerCase() === wpName.toLowerCase());
        }

        if (foundWp) {
            const bearing = getBearing(aircraft.position.lat, aircraft.position.lon, foundWp.location.lat, foundWp.location.lon);
            updates.targetHeading = Math.round(bearing);
            updates.clearedForILS = false;
            updates.establishedOnILS = false;
            updates.currentDirectTo = foundWp.name;
            parts.push(`procediendo directo a ${foundWp.name}`);
        } else {
             parts.push(`directo a... punto no encontrado`);
        }
    }

    // Parse Altitude
    const altMatch = t.match(/nivel\s+(?:de\s+)?(?:vuelo\s+)?(\d+)/);
    if (altMatch) {
        const val = parseInt(altMatch[1]);
        updates.targetAltitude = val;
        if (val > aircraft.altitude) parts.push(`ascendiendo nivel ${val}`);
        else parts.push(`descendiendo nivel ${val}`);
        updates.clearedForILS = false;
    }

    // Parse Speed
    const spdMatch = t.match(/(?:velocidad\s+(?:a\s+)?|nudos\s+)(\d+)/);
    if (spdMatch) {
        const val = parseInt(spdMatch[1]);
        updates.targetSpeed = val;
        parts.push(`velocidad ${val} nudos indicados`);
    }

    // Parse ILS / Landing
    if (t.includes('autorizado aproximación ils') || t.includes('autorizado para aterrizar')) {
        updates.clearedForILS = true;
        updates.currentDirectTo = null;

        // Smart phraseology: Detect if close to alternate
        let runway = airport ? airport.runwayName : 'activa';
        if (airport && airport.alternates) {
            const distToMain = getDistanceNM(aircraft.position.lat, aircraft.position.lon, airport.location.lat, airport.location.lon);
            let closestAltDist = distToMain;

            for (const alt of airport.alternates) {
                const d = getDistanceNM(aircraft.position.lat, aircraft.position.lon, alt.location.lat, alt.location.lon);
                if (d < closestAltDist && d < 20) {
                    closestAltDist = d;
                    runway = `${alt.name} pista ${alt.runwayName}`;
                }
            }
        }

        parts.push(`autorizado para aterrizar ILS ${runway}`);
    } else if (t.includes('cancele aproximación')) {
        updates.clearedForILS = false;
        parts.push("cancelando aproximación");
    }

    const spokenCallsign = getSpokenCallsign(aircraft.callsign);

    let responseText = "";
    if (parts.length > 0) {
        const instructionText = parts.join(', ');
        responseText = `${instructionText.charAt(0).toUpperCase() + instructionText.slice(1)}, ${spokenCallsign}.`;
    } else {
        responseText = `No le copié, repita instrucción, ${spokenCallsign}.`;
    }

    return { updates, response: responseText };
};

// Generate realistic Volcanic Ash Cone for Popocatépetl
const generateAshCloud = (windDir: number) => {
    const POPO_LAT = 19.0228;
    const POPO_LON = -98.6278;

    // Cone spreads out with wind
    // Length: ~60 NM
    const length = 60;

    const p1 = { lat: POPO_LAT, lon: POPO_LON };

    // Cone width +/- 15 degrees from wind direction
    const dirLeft = (windDir - 15 + 360) % 360;
    const dirRight = (windDir + 15) % 360;

    const p2 = getDestinationPoint(POPO_LAT, POPO_LON, dirLeft, length);
    const p3 = getDestinationPoint(POPO_LAT, POPO_LON, dirRight, length);

    return {
        points: [p1, p2, p3],
        maxAltitude: 25000 // FL250
    };
};

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>({
    isPlaying: false,
    isGameOver: false,
    level: null,
    score: 0,
    landedCount: 0,
    separationIncidents: 0,
    timeElapsed: 0,
    message: null,
    gameTier: 0,
    windSpeed: 5,
    windDirection: 60,
    weatherSeverity: 0, // Visual storm intensity
    runwayStatus: 'OPEN',
    closureReason: null,
    closureTimer: 0,
    ashCloud: null,
    tutorialCompleted: false,
    showTutorialPanel: true
  });

  const [aircraft, setAircraft] = useState<Aircraft[]>([]);
  const aircraftRef = useRef<Aircraft[]>([]); 
  const [selectedAircraftId, setSelectedAircraftId] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [radioHistory, setRadioHistory] = useState<RadioMessage[]>([]);
  const [isProcessingRadio, setIsProcessingRadio] = useState(false);

  // Scoring Refs to avoid stale closures
  const scoreRef = useRef(0);
  const landedRef = useRef(0);
  const incidentsRef = useRef(0);

  // Voice Settings State
  const [availableVoices, setAvailableVoices] = useState<SpeechSynthesisVoice[]>([]);
  const [selectedVoiceURI, setSelectedVoiceURI] = useState<string | null>(null);

  // Audio Context for Alerts
  const audioContextRef = useRef<AudioContext | null>(null);
  const lastAlertTime = useRef<number>(0);

  const lastSpawnTime = useRef<number>(0);
  const nextSpawnDelay = useRef<number>(0);
  const tickCount = useRef<number>(0);
  const gameTierRef = useRef(0);

  // Pending Updates State (Lifted from ControlPanel)
  const [pendingUpdates, setPendingUpdates] = useState<PendingUpdates>({
      heading: null,
      altitude: null,
      speed: null,
      directTo: null,
      clearedForILS: false
  });

  // Sync ref with state
  useEffect(() => {
    aircraftRef.current = aircraft;
  }, [aircraft]);

  // Load Voices
  useEffect(() => {
    const loadVoices = () => {
        const voices = window.speechSynthesis.getVoices();
        // Priority: Spanish voices, preferably Google (Neural)
        const spanishVoices = voices.filter(v => v.lang.toLowerCase().includes('es'));
        setAvailableVoices(spanishVoices);
        if (!selectedVoiceURI && spanishVoices.length > 0) {
            const mx = spanishVoices.find(v => v.lang === 'es-MX' && v.name.includes('Google'));
            if (mx) setSelectedVoiceURI(mx.voiceURI);
            else setSelectedVoiceURI(spanishVoices[0].voiceURI);
        }
    };
    loadVoices();
    window.speechSynthesis.onvoiceschanged = loadVoices;
  }, []);

  const initAudio = () => {
      if (!audioContextRef.current) {
          audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
      }
      if (audioContextRef.current.state === 'suspended') {
          audioContextRef.current.resume();
      }
  };

  const playAlertSound = (type: 'WARNING' | 'CRITICAL') => {
      if (!audioContextRef.current || Date.now() - lastAlertTime.current < 800) return;
      const ctx = audioContextRef.current;
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.connect(gain);
      gain.connect(ctx.destination);

      if (type === 'CRITICAL') {
          osc.type = 'sawtooth';
          osc.frequency.setValueAtTime(800, ctx.currentTime);
          osc.frequency.linearRampToValueAtTime(1200, ctx.currentTime + 0.1);
          osc.frequency.linearRampToValueAtTime(800, ctx.currentTime + 0.2);
          gain.gain.setValueAtTime(0.3, ctx.currentTime);
          gain.gain.linearRampToValueAtTime(0, ctx.currentTime + 0.4);
          osc.start();
          osc.stop(ctx.currentTime + 0.4);
      } else {
          osc.type = 'sine';
          osc.frequency.setValueAtTime(600, ctx.currentTime);
          osc.frequency.exponentialRampToValueAtTime(300, ctx.currentTime + 0.2);
          gain.gain.setValueAtTime(0.1, ctx.currentTime);
          gain.gain.linearRampToValueAtTime(0, ctx.currentTime + 0.3);
          osc.start();
          osc.stop(ctx.currentTime + 0.3);
      }
      lastAlertTime.current = Date.now();
  };

  const playRadarContactSound = () => {
    if (!audioContextRef.current) return;
    const ctx = audioContextRef.current;
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.connect(gain);
    gain.connect(ctx.destination);
    osc.type = 'sine';
    osc.frequency.setValueAtTime(2000, ctx.currentTime); 
    gain.gain.setValueAtTime(0.05, ctx.currentTime); 
    gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.15); 
    osc.start();
    osc.stop(ctx.currentTime + 0.15);
  };

  const playRadioBlip = () => {
    if (!audioContextRef.current) return;
    if (audioContextRef.current.state === 'suspended') {
        audioContextRef.current.resume();
    }
    const ctx = audioContextRef.current;
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.connect(gain);
    gain.connect(ctx.destination);
    osc.type = 'sine';
    osc.frequency.setValueAtTime(800, ctx.currentTime);
    gain.gain.setValueAtTime(0.1, ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.1);
    osc.start();
    osc.stop(ctx.currentTime + 0.1);
  };

  // Reset pending updates
  useEffect(() => {
      if (selectedAircraftId) {
          const plane = aircraft.find(p => p.id === selectedAircraftId);
          if (plane) {
              setPendingUpdates({
                  heading: Math.round(plane.targetHeading),
                  altitude: Math.round(plane.targetAltitude),
                  speed: Math.round(plane.targetSpeed),
                  directTo: null,
                  clearedForILS: plane.clearedForILS
              });
          }
      } else {
          setPendingUpdates({
              heading: null,
              altitude: null,
              speed: null,
              directTo: null,
              clearedForILS: false
          });
      }
  }, [selectedAircraftId]);

  // Enhanced Natural TTS
  const speakOffline = (text: string, forcedVoiceURI?: string) => {
      window.speechSynthesis.cancel();
      let spokenText = text;
      // Phonetic corrections
      spokenText = spokenText.replace(/\bURNOK\b/g, "Urnok");
      spokenText = spokenText.replace(/\bSUTAS\b/g, "Sutas");
      spokenText = spokenText.replace(/\bMATEO\b/g, "Mateo");
      spokenText = spokenText.replace(/\bPLAZA\b/g, "Plaza");
      spokenText = spokenText.replace(/\bAPAN\b/g, "Apan");

      const utterance = new SpeechSynthesisUtterance(spokenText);
      let voice = null;

      // Try to find the requested voice, or a Google voice, or best available Spanish
      if (forcedVoiceURI) {
          voice = availableVoices.find(v => v.voiceURI === forcedVoiceURI);
      }
      if (!voice) {
          // Priority to "Google" voices as they are usually neural/better
          voice = availableVoices.find(v => v.lang.includes('es') && v.name.includes('Google'));
      }
      if (!voice && selectedVoiceURI) {
          voice = availableVoices.find(v => v.voiceURI === selectedVoiceURI);
      }
      if (!voice && availableVoices.length > 0) {
          voice = availableVoices[0];
      }

      if (voice) utterance.voice = voice;

      // Add slight random variation to pitch/rate if it's a pilot (implied by forcedVoiceURI usage)
      if (forcedVoiceURI) {
          // Generate a pseudo-random seed from the voiceURI length or characters
          const seed = forcedVoiceURI.length; 
          utterance.pitch = 0.9 + (seed % 4) * 0.05; // 0.9 to 1.1
          utterance.rate = 1.0 + (seed % 3) * 0.05; // 1.0 to 1.15
      } else {
          // ATC / System voice
          utterance.rate = 1.1; 
          utterance.pitch = 1.0;
      }

      window.speechSynthesis.speak(utterance);
  };

  // Helper to calculate spawn position
  const calculateSpawnPosition = (airport: Airport, entryPoint: Waypoint, distanceOffset: number = 0) => {
    const bearingOut = getBearing(airport.location.lat, airport.location.lon, entryPoint.location.lat, entryPoint.location.lon);
    const distToEntry = getDistanceNM(airport.location.lat, airport.location.lon, entryPoint.location.lat, entryPoint.location.lon);
    const spawnDist = distToEntry + 30.0 + distanceOffset; 
    const spawnPos = getDestinationPoint(airport.location.lat, airport.location.lon, bearingOut, spawnDist);
    const inboundHeading = (bearingOut + 180) % 360;
    return { spawnPos, inboundHeading };
  };

  const getSafeSpawnPoint = useCallback((airport: Airport, currentPlanes: Aircraft[]): Waypoint | null => {
    const entryPoints = airport.waypoints.filter(wp => wp.isEntry);
    const validEntryPoints = entryPoints.filter(wp => {
        const { spawnPos } = calculateSpawnPosition(airport, wp);
        const hasConflict = currentPlanes.some(p => {
             if (p.status === FlightStatus.LANDED) return false;
             const dist = getDistanceNM(spawnPos.lat, spawnPos.lon, p.position.lat, p.position.lon);
             return dist < SPAWN_SEPARATION_NM;
        });
        return !hasConflict;
    });
    if (validEntryPoints.length === 0) return null;
    const shuffled = [...validEntryPoints].sort(() => 0.5 - Math.random());
    return shuffled[0];
  }, []);

  const spawnPlane = useCallback((template: Partial<Aircraft>, airport: Airport, entryPoint: Waypoint, voiceURI?: string, distanceOffset: number = 0): Aircraft => {
    const { spawnPos, inboundHeading } = calculateSpawnPosition(airport, entryPoint, distanceOffset);
    return {
      id: Math.random().toString(36).substr(2, 9),
      callsign: template.callsign || 'UNK000',
      model: template.model || 'Unknown',
      airline: template.airline || 'Unknown',
      position: spawnPos,
      history: [],
      heading: inboundHeading,
      speed: 280, 
      altitude: 24000 + (Math.floor(Math.random()*4)*1000), 
      status: FlightStatus.INBOUND,
      targetAltitude: 24000, 
      targetHeading: inboundHeading,
      targetSpeed: 280,
      fuel: 100,
      turnDelay: 0,
      clearedForILS: false,
      establishedOnILS: false,
      currentDirectTo: null,
      voiceURI: voiceURI, 
      squawk: '1200',
      isTutorial: false 
    };
  }, []);

  const spawnRandomPlane = async (airport: Airport) => {
    if (aircraftRef.current.filter(p => p.status !== FlightStatus.LANDED).length >= 10) return;
    const safeWp = getSafeSpawnPoint(airport, aircraftRef.current);
    if (!safeWp) return;

    // Use Local Generator instead of Gemini
    let template = generateLocalFlight(airport.code);

    let uniqueCallsign = template.callsign || `MX${Math.floor(Math.random()*900)+100}`;
    let attempts = 0;
    while (aircraftRef.current.some(p => p.callsign === uniqueCallsign) && attempts < 20) {
        const match = uniqueCallsign.match(/^([A-Z]+)(\d+)$/);
        if (match) {
            const code = match[1];
            const newNum = Math.floor(Math.random() * 9000) + 100;
            uniqueCallsign = `${code}${newNum}`;
        } else {
             uniqueCallsign = `MX${Math.floor(Math.random()*9000)+100}`;
        }
        attempts++;
    }
    template.callsign = uniqueCallsign;

    let randomVoiceURI = undefined;
    const voices = availableVoices.length > 0 ? availableVoices : window.speechSynthesis.getVoices().filter(v => v.lang.toLowerCase().includes('es'));
    if (voices.length > 0) {
        // Filter for Google voices if possible for better quality
        const googleVoices = voices.filter(v => v.name.includes('Google'));
        const pool = googleVoices.length > 0 ? googleVoices : voices;
        const randomVoice = pool[Math.floor(Math.random() * pool.length)];
        randomVoiceURI = randomVoice.voiceURI;
    }

    const newPlane = spawnPlane(template, airport, safeWp, randomVoiceURI);
    setAircraft(prev => [...prev, newPlane]);
    playRadarContactSound();

    const date = new Date();
    const hour = date.getHours();
    let greeting = 'Buenas noches, Torre México';
    if (hour >= 5 && hour < 12) greeting = 'Buenos días, Torre México';
    else if (hour >= 12 && hour < 19) greeting = 'Torre México, Buenas tardes';
    const spokenCallsign = getSpokenCallsign(newPlane.callsign);
    speakOffline(`${greeting}, ${spokenCallsign}, contacto radar.`, randomVoiceURI);
  };

  const startLevel = async (airport: Airport) => {
    initAudio(); 
    scoreRef.current = 0;
    landedRef.current = 0;
    incidentsRef.current = 0;
    gameTierRef.current = 0;
    setLoading(true);

    // Generate initial traffic locally
    let flightTemplates: Partial<Aircraft>[] = [];
    for(let i=0; i<3; i++) {
        flightTemplates.push(generateLocalFlight(airport.code));
    }

    setLoading(false);
    setGameState({
      isPlaying: true,
      isGameOver: false,
      level: airport,
      score: 0.0,
      landedCount: 0,
      separationIncidents: 0,
      timeElapsed: 0,
      message: `Torre ${airport.code} operativa. Monitoreando frecuencia 118.1.`,
      gameTier: 0,
      windSpeed: 5,
      windDirection: 60,
      weatherSeverity: 0,
      runwayStatus: 'OPEN',
      closureReason: null,
      closureTimer: 0,
      ashCloud: null,
      tutorialCompleted: false,
      showTutorialPanel: true
    });
    setRadioHistory([]);

    const initialPlanes: Aircraft[] = [];
    const entryPoints = airport.waypoints.filter(w => w.isEntry);
    const voices = availableVoices.length > 0 ? availableVoices : window.speechSynthesis.getVoices().filter(v => v.lang.toLowerCase().includes('es'));
    const shuffledEntryPoints = [...entryPoints].sort(() => 0.5 - Math.random());

    for (let i = 0; i < flightTemplates.length; i++) {
        const tmpl = flightTemplates[i];
        let wp = shuffledEntryPoints[i % shuffledEntryPoints.length];

        // Voice Selection
        let randomVoiceURI = undefined;
        if (voices.length > 0) {
            const googleVoices = voices.filter(v => v.name.includes('Google'));
            const pool = googleVoices.length > 0 ? googleVoices : voices;
            const randomVoice = pool[Math.floor(Math.random() * pool.length)];
            randomVoiceURI = randomVoice.voiceURI;
        }

        if (i === 0 && airport.code === 'MMMX') {
            const mateoFix = airport.waypoints.find(w => w.name === 'MATEO');
            if (mateoFix) {
                const startLat = mateoFix.location.lat;
                const startLon = mateoFix.location.lon;
                const tutorialSpawn = getDestinationPoint(startLat, startLon, 315, 12);
                const tutorialPlane: Aircraft = {
                    id: Math.random().toString(36).substr(2, 9),
                    callsign: tmpl.callsign || 'AMX543',
                    model: 'B737',
                    airline: 'Aeromexico',
                    position: tutorialSpawn,
                    history: [],
                    heading: 135,
                    speed: 240, 
                    altitude: 12000, 
                    status: FlightStatus.INBOUND,
                    targetAltitude: 12000,
                    targetHeading: 135,
                    targetSpeed: 240,
                    fuel: 100,
                    turnDelay: 0,
                    clearedForILS: false,
                    establishedOnILS: false,
                    currentDirectTo: null, 
                    voiceURI: randomVoiceURI,
                    squawk: '1200',
                    isTutorial: true 
                };
                initialPlanes.push(tutorialPlane);
                continue; 
            }
        }

        if (wp) {
             let uniqueCallsign = tmpl.callsign || `MX${Math.floor(Math.random()*999)}`;
             let attempts = 0;
             const isDuplicate = (cs: string) => 
                initialPlanes.some(p => p.callsign === cs) || 
                aircraftRef.current.some(p => p.callsign === cs);

             while (isDuplicate(uniqueCallsign) && attempts < 20) {
                const match = uniqueCallsign.match(/^([A-Z]+)(\d+)$/);
                if (match) {
                    const code = match[1];
                    const newNum = Math.floor(Math.random() * 9000) + 100;
                    uniqueCallsign = `${code}${newNum}`;
                } else {
                     uniqueCallsign = `MX${Math.floor(Math.random()*9000)+100}`;
                }
                attempts++;
             }
             tmpl.callsign = uniqueCallsign;
             const newPlane = spawnPlane(tmpl, airport, wp, randomVoiceURI, i * 15);
             initialPlanes.push(newPlane);
        }
    }
    setAircraft(initialPlanes);
    lastSpawnTime.current = Date.now();
    nextSpawnDelay.current = airport.spawnRate; 
  };

  const handleUpdateAircraft = (id: string, updates: Partial<Aircraft>) => {
    setAircraft(prev => prev.map(p => {
        if (p.id !== id) return p;
        let newTurnDelay = p.turnDelay;
        if (updates.targetHeading !== undefined && Math.abs(updates.targetHeading - p.targetHeading) > 1) {
            newTurnDelay = PILOT_REACTION_DELAY_TICKS;
        }
        return { ...p, ...updates, turnDelay: newTurnDelay };
    }));
  };

  const handleSendCommand = (text: string) => {
    if (!selectedAircraftId) return;
    const selectedPlane = aircraft.find(p => p.id === selectedAircraftId);
    if (!selectedPlane) return;
    const atcMessage: RadioMessage = { id: Date.now().toString(), sender: 'ATC', text: text, timestamp: Date.now() };
    setRadioHistory(prev => [...prev, atcMessage]);
    setIsProcessingRadio(true);
    if (selectedPlane.squawk === '7600') {
        setTimeout(() => { setIsProcessingRadio(false); }, 2000);
        return;
    }
    setTimeout(() => {
        const offlineData = generateOfflinePilotResponse(text, selectedPlane, gameState.level);
        handleUpdateAircraft(selectedPlane.id, offlineData.updates);
        const pilotMessage: RadioMessage = { id: (Date.now() + 1).toString(), sender: 'PILOT', callsign: selectedPlane.callsign, text: offlineData.response, timestamp: Date.now() };
        setRadioHistory(prev => [...prev, pilotMessage]);
        speakOffline(offlineData.response, selectedPlane.voiceURI);
        setIsProcessingRadio(false);
    }, 600); 
  };

  const handleRadarInteraction = (updates: { heading?: number | null, directTo?: string | null }) => {
      setPendingUpdates(prev => ({
          ...prev,
          heading: updates.heading !== undefined ? updates.heading : (updates.directTo ? null : prev.heading),
          directTo: updates.directTo !== undefined ? updates.directTo : (updates.heading ? null : prev.directTo),
          clearedForILS: false
      }));
  };

  const checkForLevelProgression = (currentScore: number) => {
      const currentTier = gameTierRef.current;
      let newTier = currentTier;
      let notification = null;
      let newWeatherSeverity = 0;

      if (currentScore > 30 && currentTier < 3) {
          newTier = 3;
          notification = "¡NIVEL 3! EMERGENCIAS ACTIVAS.";
      } else if (currentScore > 20 && currentTier < 2) {
          newTier = 2;
          notification = "¡NIVEL 2! ACTIVIDAD VOLCÁNICA POSIBLE.";
      } else if (currentScore > 10 && currentTier < 1) {
          newTier = 1;
          notification = "¡NIVEL 1! AEROPUERTOS ALTERNOS DISPONIBLES.";
      }

      if (currentScore > 10) {
          const progress = Math.min(1, (currentScore - 10) / 20); 
          newWeatherSeverity = progress * 0.7;
      }

      if (newTier !== currentTier) {
          gameTierRef.current = newTier;
          setGameState(prev => ({ ...prev, gameTier: newTier, message: notification, weatherSeverity: newWeatherSeverity }));
          if (notification) speakOffline(notification);
      } else if (Math.abs(newWeatherSeverity - gameState.weatherSeverity) > 0.05) {
          setGameState(prev => ({ ...prev, weatherSeverity: newWeatherSeverity }));
      }
  };

  const generateTutorialHints = (plane: Aircraft, airport: Airport): string | null => {
      if (plane.status === FlightStatus.LANDED || plane.status === FlightStatus.CRASHED) return null;
      if (!plane.isTutorial || gameState.tutorialCompleted) return null;
      const mateo = airport.waypoints.find(w => w.name === 'MATEO');
      const plaza = airport.waypoints.find(w => w.name === 'PLAZA');
      if (!mateo || !plaza) return null;
      const distToMateo = getDistanceNM(plane.position.lat, plane.position.lon, mateo.location.lat, mateo.location.lon);
      const distToPlaza = getDistanceNM(plane.position.lat, plane.position.lon, plaza.location.lat, plaza.location.lon);
      const distToAirport = getDistanceNM(plane.position.lat, plane.position.lon, airport.location.lat, airport.location.lon);

      if (distToMateo > 2 && plane.currentDirectTo !== 'MATEO' && distToPlaza > 10) {
          if (plane.altitude > 11000) return "DESCIENDA A 2000!";
          return "DIRECTO A MATEO!";
      }
      if (distToMateo < 5 && distToPlaza > 5) {
          if (plane.speed > 210) return "REDUZCA VELOCIDAD 200!";
          if (plane.currentDirectTo !== 'MATEO') return "DIRECTO A PLAZA";
          if (plane.altitude > 10000) return "DESCIENDA A 2000";
      }
      if (distToPlaza < 8 || (distToAirport < 20 && distToAirport > 5)) {
          if (plane.clearedForILS) return "ILS ARMADO (OK)";
          let angleDiff = Math.abs(plane.heading - airport.runwayHeading);
          if (angleDiff > 180) angleDiff = 360 - angleDiff;
          const bearingToAirport = getBearing(plane.position.lat, plane.position.lon, airport.location.lat, airport.location.lon);
          let bearingDiff = Math.abs(bearingToAirport - airport.runwayHeading);
          if (bearingDiff > 180) bearingDiff = 360 - bearingDiff;
          const lateralDist = Math.sin(bearingDiff * Math.PI / 180) * distToAirport;
          const bearingFromAirport = getBearing(airport.location.lat, airport.location.lon, plane.position.lat, plane.position.lon);
          const backCourse = (airport.runwayHeading + 180) % 360;
          let angleFromCenter = Math.abs(bearingFromAirport - backCourse);
          if (angleFromCenter > 180) angleFromCenter = 360 - angleFromCenter;

          if (lateralDist < 2.5) {
              if (angleDiff > 5) return `DIRECTO A MEX, ARME ILS!`;
              if (plane.altitude > 2100) return "BAJE A 2000";
              return "ARME ILS";
          } else {
              if (angleFromCenter < 16) return "INTERCEPTE (RUMBO 090)";
              else return "ACÉRCATE A LA ZONA DE CAPTURA ILS";
          }
      }
      return null;
  };

  const renderTutorialPanel = () => {
      if (!gameState.showTutorialPanel) return null;
      if (gameState.tutorialCompleted) {
          return (
            <div className="pointer-events-auto bg-emerald-900/95 border-l-4 border-emerald-400 p-4 rounded shadow-xl max-w-sm backdrop-blur-sm animate-fade-in mt-2 relative">
                <button 
                    onClick={() => setGameState(prev => ({...prev, showTutorialPanel: false}))}
                    className="absolute top-2 right-2 text-emerald-200 hover:text-white font-bold"
                >✕</button>
                <h3 className="text-emerald-300 font-bold text-sm mb-2 uppercase tracking-wider border-b border-emerald-700 pb-1">¡FELICIDADES!</h3>
                <p className="text-white text-xs leading-relaxed font-sans font-bold">Has completado el entrenamiento básico.</p>
                <p className="text-emerald-100 text-xs leading-relaxed font-sans mt-2">Ahora el control del espacio aéreo es tuyo. Te esperan muchos desafíos por delante. ¡Buena suerte!</p>
            </div>
          );
      }
      const selected = aircraft.find(a => a.id === selectedAircraftId);
      const mateo = gameState.level?.waypoints.find(w => w.name === 'MATEO');
      let phase = "INTRODUCCIÓN";
      let text = "Selecciona el avión 'Tutorial' para comenzar.";
      if (selected && mateo) {
          const distToMateo = getDistanceNM(selected.position.lat, selected.position.lon, mateo.location.lat, mateo.location.lon);
          const distToAirport = getDistanceNM(selected.position.lat, selected.position.lon, gameState.level!.location.lat, gameState.level!.location.lon);
          if (distToMateo > 5 && distToAirport > 20) {
              phase = "FASE 1: NAVEGACIÓN VOR";
              text = "Los hexágonos son VORs. Envía el avión 'Directo a MATEO' y desciende, debes dar la siguiente indicación al llegar al VOR o antes, si no lo haces el avión entrará en patrón de espera en esa ubicación.";
          } else if (distToAirport > 15) {
              phase = "FASE 2: NAVEGACIÓN DE ÁREA";
              text = "Los triángulos son FIXes. Al pasar MATEO, ve 'Directo a PLAZA' y reduce velocidad. PLAZA te servirá para alinear el vuelo con la linea de captura ILS";
          } else {
              phase = "FASE 3: APROXIMACIÓN ILS";
              text = "La LÍNEA AZUL es el ILS (Instrument Landing System). Vuela paralelo a ella (060°) y presiona 'ILS APP' para aterrizar en piloto automático.";
          }
      }
      return (
        <div className="pointer-events-auto bg-blue-900/90 border-l-4 border-cyan-400 p-4 rounded shadow-lg max-w-sm backdrop-blur-sm animate-fade-in mt-2">
            <h3 className="text-cyan-300 font-bold text-sm mb-1 uppercase tracking-wider border-b border-blue-700 pb-1">{phase}</h3>
            <p className="text-white text-xs leading-relaxed font-sans">{text}</p>
        </div>
      );
  };

  const processGameEvents = (tick: number, activePlanes: Aircraft[]) => {
      const tier = gameTierRef.current;
      const updates: Partial<GameState> = {};
      let updated = false;

      if (tier >= 1 && tick % 50 === 0) { 
          let newSpeed = gameState.windSpeed + (Math.random() > 0.5 ? 1 : -1);
          newSpeed = Math.max(5, Math.min(30, newSpeed));
          let newDir = gameState.windDirection + (Math.random() > 0.5 ? 5 : -5);
          newDir = (newDir + 360) % 360;
          updates.windSpeed = newSpeed;
          updates.windDirection = newDir;
          updated = true;

          // Update Ash Cloud if active
          if (gameState.ashCloud && tier >= 2) {
              updates.ashCloud = generateAshCloud(newDir);
          }
      }

      if (tier >= 2) {
          if (gameState.runwayStatus === 'CLOSED') {
              if (gameState.closureTimer <= 0) {
                  updates.runwayStatus = 'OPEN';
                  updates.closureReason = null;
                  updates.ashCloud = null; // Clear cloud
                  updates.message = "PISTA REABIERTA. OPERACIONES NORMALES.";
                  speakOffline("Pista reabierta. Operaciones normales.");
                  updated = true;
              } else {
                  updates.closureTimer = gameState.closureTimer - GAME_LOOP_MS;
                  updated = true;
              }
          } else if (Math.random() < 0.0001) { // Reduced frequency ~1/10000 ticks
              const reason = Math.random() > 0.3 ? "CENIZA VOLCÁNICA" : "SISMO LEVE";
              updates.runwayStatus = 'CLOSED';
              updates.closureReason = reason;
              updates.closureTimer = 120000; // 2 minutes closure (120,000 ms)

              if (reason === "CENIZA VOLCÁNICA") {
                   updates.ashCloud = generateAshCloud(gameState.windDirection);
              }

              const msg = `ALERTA: PISTA CERRADA POR ${reason}. REVISIÓN EN CURSO.`;
              updates.message = msg;
              speakOffline(msg);
              updated = true;

              activePlanes.forEach(p => {
                  // Only force Go Around if going to Main Airport ILS, not Alternates
                  const goingToAlternate = gameState.level?.alternates?.some(alt => getDistanceNM(p.position.lat, p.position.lon, alt.location.lat, alt.location.lon) < 15);
                  if (!goingToAlternate && (p.establishedOnILS || p.clearedForILS)) {
                       handleUpdateAircraft(p.id, {
                           clearedForILS: false,
                           establishedOnILS: false,
                           status: FlightStatus.GO_AROUND,
                           targetHeading: gameState.level!.runwayHeading,
                           targetAltitude: 2000,
                           targetSpeed: 200
                       });
                  }
              });
          }
      }

      if (tier >= 3 && tick % 100 === 0) { 
           if (Math.random() < 0.02) { 
               const candidates = activePlanes.filter(p => p.squawk === '1200' && p.status !== FlightStatus.LANDED);
               if (candidates.length > 0) {
                   const victim = candidates[Math.floor(Math.random() * candidates.length)];
                   const type = Math.random() > 0.7 ? '7700' : '7600'; 
                   handleUpdateAircraft(victim.id, { squawk: type });
                   if (type === '7700') {
                       speakOffline(`Mayday, mayday. ${getSpokenCallsign(victim.callsign)} declarando emergencia.`, victim.voiceURI);
                   }
               }
           }
      }
      if (updated) setGameState(prev => ({ ...prev, ...updates }));
  };

  useEffect(() => {
    if (!gameState.isPlaying || gameState.isGameOver || !gameState.level) return;
    const interval = setInterval(() => {
      tickCount.current += 1;
      if (Date.now() - lastSpawnTime.current > nextSpawnDelay.current) {
          spawnRandomPlane(gameState.level!);
          lastSpawnTime.current = Date.now();
          nextSpawnDelay.current = gameState.level!.spawnRate + (Math.random() * 5000);
      }
      setAircraft(prevAircraft => {
        let highestAlert: 'NONE' | 'WARNING' | 'CRITICAL' = 'NONE';
        const activePlanes = prevAircraft.filter(p => p.status !== FlightStatus.LANDED && p.status !== FlightStatus.CRASHED);
        let tutorialJustCompleted = false;
        checkForLevelProgression(scoreRef.current);
        processGameEvents(tickCount.current, activePlanes);

        const alertMap = new Map<string, 'NONE' | 'WARNING' | 'CRITICAL'>();
        prevAircraft.forEach(p => alertMap.set(p.id, 'NONE'));
        for (let i = 0; i < prevAircraft.length; i++) {
            const p1 = prevAircraft[i];
            if (p1.status === FlightStatus.LANDED || p1.status === FlightStatus.CRASHED) continue;
            for (let j = i + 1; j < prevAircraft.length; j++) {
                const p2 = prevAircraft[j];
                if (p2.status === FlightStatus.LANDED || p2.status === FlightStatus.CRASHED) continue;
                const dist = getDistanceNM(p1.position.lat, p1.position.lon, p2.position.lat, p2.position.lon);
                const altDist = Math.abs(p1.altitude - p2.altitude);
                if (dist < COLLISION_NM && altDist < SEPARATION_ALT_THRESHOLD) {
                    alertMap.set(p1.id, 'CRITICAL');
                    alertMap.set(p2.id, 'CRITICAL');
                    highestAlert = 'CRITICAL';
                } else if (dist < WARNING_NM && altDist < SEPARATION_ALT_THRESHOLD) {
                    if (alertMap.get(p1.id) !== 'CRITICAL') alertMap.set(p1.id, 'WARNING');
                    if (alertMap.get(p2.id) !== 'CRITICAL') alertMap.set(p2.id, 'WARNING');
                    if (highestAlert !== 'CRITICAL') highestAlert = 'WARNING';
                }
            }
        }
        if (highestAlert === 'CRITICAL') playAlertSound('CRITICAL');
        else if (highestAlert === 'WARNING') playAlertSound('WARNING');

        const updatedAircraft = prevAircraft.map(plane => {
            if (plane.status === FlightStatus.LANDED || plane.status === FlightStatus.CRASHED) return plane;
            const airport = gameState.level!;
            let hdg = plane.heading;
            let alt = plane.altitude;
            let spd = plane.speed;
            let established = plane.establishedOnILS;
            let targetAlt = plane.targetAltitude;
            let targetSpd = plane.targetSpeed;
            let currentDelay = plane.turnDelay;
            let currentTargetHeading = plane.targetHeading;
            const distToAirport = getDistanceNM(plane.position.lat, plane.position.lon, airport.location.lat, airport.location.lon);

            // Check for Alternate Airport ILS capture
            let targetRunwayHeading = airport.runwayHeading;
            let targetLocation = airport.location;
            let isAlternate = false;

            if (plane.clearedForILS && !established) {
                // Check Main Airport (Only if OPEN)
                if (gameState.runwayStatus === 'OPEN') {
                    // Logic below
                } 
                // Check Alternates (Level 1+)
                if (airport.alternates && gameState.gameTier >= 1) {
                     for (const altAirport of airport.alternates) {
                         const d = getDistanceNM(plane.position.lat, plane.position.lon, altAirport.location.lat, altAirport.location.lon);
                         if (d < 20) {
                             targetRunwayHeading = altAirport.runwayHeading;
                             targetLocation = altAirport.location;
                             isAlternate = true;
                             break;
                         }
                     }
                }
            } else if (established) {
                // If established, we need to know WHERE. 
                // Simplified: Assume if established, they stay established on the current target path.
                // Re-calculating nearest airport to maintain heading
                 if (airport.alternates && gameState.gameTier >= 1) {
                     for (const altAirport of airport.alternates) {
                         const d = getDistanceNM(plane.position.lat, plane.position.lon, altAirport.location.lat, altAirport.location.lon);
                         if (d < 15) {
                             targetRunwayHeading = altAirport.runwayHeading;
                             targetLocation = altAirport.location;
                             isAlternate = true;
                             break;
                         }
                     }
                 }
            }

            if (plane.clearedForILS && !plane.establishedOnILS) {
                 // Capture Logic for determined target (Main or Alternate)
                 const canCaptureMain = !isAlternate && gameState.runwayStatus === 'OPEN';

                 if (canCaptureMain || isAlternate) {
                    const dLon = (targetLocation.lon - plane.position.lon) * Math.PI / 180;
                    const lat1 = plane.position.lat * Math.PI / 180;
                    const lat2 = targetLocation.lat * Math.PI / 180;
                    const y = Math.sin(dLon) * Math.cos(lat2);
                    const x = Math.cos(lat1) * Math.sin(lat2) - Math.sin(lat1) * Math.cos(lat2) * Math.cos(dLon);
                    const bearingToTarget = (Math.atan2(y, x) * 180 / Math.PI + 360) % 360;

                    let alignmentError = Math.abs(bearingToTarget - targetRunwayHeading);
                    if (alignmentError > 180) alignmentError = 360 - alignmentError;
                    let headingDiff = Math.abs(plane.heading - targetRunwayHeading);
                    if (headingDiff > 180) headingDiff = 360 - headingDiff;
                    const distToTarget = getDistanceNM(plane.position.lat, plane.position.lon, targetLocation.lat, targetLocation.lon);

                    if (alignmentError < 2.0 && headingDiff < 30 && distToTarget < 25) {
                        established = true;
                    }
                 }
            }

            if (established) {
                if (!isAlternate && gameState.runwayStatus === 'CLOSED') {
                    established = false;
                } else {
                    hdg = targetRunwayHeading;
                    const dist = getDistanceNM(plane.position.lat, plane.position.lon, targetLocation.lat, targetLocation.lon);
                    targetAlt = Math.max(0, dist * 320); 
                    targetSpd = 140; 
                }
            } else {
                if (plane.currentDirectTo) {
                    const wp = airport.waypoints.find(w => w.name === plane.currentDirectTo);
                    if (wp) currentTargetHeading = getBearing(plane.position.lat, plane.position.lon, wp.location.lat, wp.location.lon);
                }
                if (currentDelay > 0) {
                    currentDelay--;
                } else {
                    let diff = currentTargetHeading - hdg;
                    if (diff < -180) diff += 360;
                    if (diff > 180) diff -= 360;
                    if (Math.abs(diff) < TURN_RATE_PER_TICK) hdg = currentTargetHeading;
                    else hdg += Math.sign(diff) * TURN_RATE_PER_TICK;
                    hdg = (hdg + 360) % 360;
                }
            }

            let altDiff = targetAlt - alt;
            if (Math.abs(altDiff) < CLIMB_RATE_PER_TICK) alt = targetAlt;
            else alt += Math.sign(altDiff) * CLIMB_RATE_PER_TICK;
            let spdDiff = targetSpd - spd;
            if (Math.abs(spdDiff) < SPEED_RATE_PER_TICK) spd = targetSpd;
            else spd += Math.sign(spdDiff) * SPEED_RATE_PER_TICK;

            let groundSpeed = spd;
            if (gameState.gameTier >= 1) {
                const windRad = (gameState.windDirection - hdg) * Math.PI / 180;
                const headwind = gameState.windSpeed * Math.cos(windRad);
                groundSpeed = spd - headwind;
            }
            const distNM = groundSpeed * (GAME_LOOP_MS / 1000 / 3600);
            const destination = getDestinationPoint(plane.position.lat, plane.position.lon, hdg, distNM);
            const newLat = destination.lat;
            const newLon = destination.lon;

            let newHistory = plane.history;
            if (tickCount.current % TRAIL_UPDATE_TICKS === 0) {
                newHistory = [...plane.history, plane.position];
                if (newHistory.length > 500) newHistory.shift(); 
            }

            let newStatus: FlightStatus = plane.status;
            const currentAlert = alertMap.get(plane.id) || 'NONE';

            // Check landing at ANY active airport (Main or Alternate)
            const distToMain = getDistanceNM(newLat, newLon, airport.location.lat, airport.location.lon);
            let landed = false;

            if (established && alt < 200) {
                if (distToMain < 0.5) landed = true;
                if (!landed && isAlternate) {
                     // Check alternate distances
                     if (airport.alternates) {
                         for (const alt of airport.alternates) {
                             if (getDistanceNM(newLat, newLon, alt.location.lat, alt.location.lon) < 0.5) {
                                 landed = true;
                                 break;
                             }
                         }
                     }
                }
            }

            if (landed) {
                newStatus = FlightStatus.LANDED;
                scoreRef.current += 1.0;
                landedRef.current += 1;
                if (plane.isTutorial) tutorialJustCompleted = true;
            }
            if (newStatus !== FlightStatus.LANDED) {
                if (currentAlert === 'CRITICAL' && plane.status !== FlightStatus.LOST_SEPARATION) {
                    incidentsRef.current += 1;
                    scoreRef.current -= 0.5;
                    newStatus = FlightStatus.LOST_SEPARATION;
                } else if (currentAlert !== 'CRITICAL' && plane.status === FlightStatus.LOST_SEPARATION) {
                    newStatus = FlightStatus.INBOUND; 
                }
            }
            let hint = null;
            if (scoreRef.current < 10 && !gameState.tutorialCompleted && !tutorialJustCompleted) {
                hint = generateTutorialHints({ ...plane, position: {lat: newLat, lon: newLon} }, gameState.level!);
            }
            return {
                ...plane,
                heading: hdg,
                altitude: alt,
                speed: spd,
                position: { lat: newLat, lon: newLon },
                history: newHistory,
                establishedOnILS: established,
                targetAltitude: targetAlt,
                targetHeading: currentTargetHeading,
                targetSpeed: targetSpd,
                status: newStatus,
                turnDelay: currentDelay,
                proximityAlert: currentAlert,
                tutorialHint: hint
            };
        });
        const updatedActivePlanes = updatedAircraft.filter(p => p.status !== FlightStatus.LANDED);
        setGameState(prev => ({
            ...prev,
            score: scoreRef.current,
            landedCount: landedRef.current,
            separationIncidents: incidentsRef.current,
            timeElapsed: prev.timeElapsed + GAME_LOOP_MS,
            tutorialCompleted: tutorialJustCompleted ? true : prev.tutorialCompleted
        }));
        if (tutorialJustCompleted) speakOffline("Tutorial completado. Buen trabajo, Controlador.");
        return updatedActivePlanes;
      });
    }, GAME_LOOP_MS);
    return () => clearInterval(interval);
  }, [gameState.isPlaying, gameState.level, gameState.isGameOver, gameState.tutorialCompleted]);

  const activeAircraft = aircraft.find(a => a.id === selectedAircraftId) || null;
  return (
    <div className="h-[100dvh] w-screen bg-slate-950 flex flex-col overflow-hidden text-slate-100 font-mono">
      <div className="absolute top-0 left-0 p-4 z-50 pointer-events-none w-full flex justify-between">
        {gameState.level && (
            <div className="flex flex-col gap-2">
                <div>
                    <div className="text-4xl font-bold text-slate-500 opacity-80">score <span className="text-slate-300">{gameState.score.toFixed(1)}</span></div>
                    <div className="text-sm text-slate-500">{gameState.landedCount} landings, {gameState.separationIncidents} incidents</div>
                    <div className="mt-2 text-emerald-500 text-xs tracking-wider uppercase drop-shadow-md font-bold">{gameState.message}</div>
                </div>
                {gameState.score < 10 && renderTutorialPanel()}
            </div>
        )}
        {gameState.level && (
            <div className="flex flex-col items-end gap-1 text-xs">
                <div className={`px-2 py-1 rounded border font-bold ${
                    gameState.runwayStatus === 'OPEN' ? 'bg-emerald-900/50 border-emerald-700 text-emerald-400' : 'bg-red-900/80 border-red-600 text-white animate-pulse'
                }`}>
                    RWY {gameState.level.runwayName}: {gameState.runwayStatus}
                    {gameState.runwayStatus === 'CLOSED' && <div className="text-[10px] opacity-80">{gameState.closureReason} ({(gameState.closureTimer/1000).toFixed(0)}s)</div>}
                </div>
                <div className="px-2 py-1 rounded border bg-slate-800/50 border-slate-700 text-slate-400">VIENTO: {gameState.windDirection.toString().padStart(3,'0')}° / {gameState.windSpeed} KT</div>
                <div className="px-2 py-1 rounded border bg-slate-800/50 border-slate-700 text-slate-500">NIVEL {gameState.gameTier}</div>
            </div>
        )}
      </div>
      <div className="flex-1 relative flex flex-col">
        {gameState.isPlaying && gameState.level ? (
          <>
            <div className="flex-1 relative">
                <RadarScreen 
                    aircraft={aircraft} 
                    airport={gameState.level} 
                    selectedAircraftId={selectedAircraftId}
                    onSelectAircraft={setSelectedAircraftId}
                    pendingUpdates={pendingUpdates}
                    onRadarInteraction={handleRadarInteraction}
                    weatherSeverity={gameState.weatherSeverity}
                    score={gameState.score}
                    gameTier={gameState.gameTier}
                    ashCloud={gameState.ashCloud}
                />
            </div>
            <div className="h-1/3 lg:h-64 z-40">
                <ControlPanel 
                    aircraft={activeAircraft}
                    airport={gameState.level}
                    pendingUpdates={pendingUpdates}
                    setPendingUpdates={setPendingUpdates}
                    radioHistory={radioHistory}
                    onSendCommand={handleSendCommand}
                    isProcessingRadio={isProcessingRadio}
                    availableVoices={availableVoices}
                    currentVoiceURI={selectedVoiceURI}
                    onVoiceChange={setSelectedVoiceURI}
                    onPlayTransmitSound={playRadioBlip}
                />
            </div>
          </>
        ) : (
          <div className="absolute inset-0 flex items-center justify-center z-50 bg-[url('https://images.unsplash.com/photo-1542296332-2e44a99cfef9?q=80&w=2666&auto=format&fit=crop')] bg-cover bg-center">
            <div className="absolute inset-0 bg-black/80 backdrop-blur-sm"></div>
            <div className="relative z-10 max-w-2xl w-full bg-slate-900/90 p-8 rounded-2xl border border-slate-700 shadow-2xl text-center">
              <h1 className="text-5xl font-bold text-white mb-2 tracking-tighter">CONTROLADOR <span className="text-emerald-500">PRO</span></h1>
              <p className="text-slate-400 mb-8 font-mono text-lg">SIMULADOR DE TRÁFICO AÉREO - MÉXICO</p>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-8">
                {AIRPORTS.map(airport => (
                  <button key={airport.code} onClick={() => startLevel(airport)} disabled={loading} className="flex flex-col items-start p-4 bg-slate-800 hover:bg-slate-700 border border-slate-600 rounded-lg transition-all group text-left">
                    <div className="flex justify-between w-full mb-2"><span className="font-bold text-white group-hover:text-emerald-400 transition-colors">{airport.name}</span><span className={`text-[10px] px-2 py-0.5 rounded border uppercase ${airport.difficulty === 'Fácil' ? 'bg-emerald-900 text-emerald-300 border-emerald-700' : airport.difficulty === 'Medio' ? 'bg-yellow-900 text-yellow-300 border-yellow-700' : 'bg-red-900 text-red-300 border-red-700'}`}>{airport.difficulty}</span></div>
                    <div className="text-xs text-slate-400 mb-1 font-mono">{airport.code} • {airport.runwayName}</div>
                    <p className="text-xs text-slate-500 line-clamp-2">{airport.description}</p>
                  </button>
                ))}
              </div>
              {loading && <div className="text-emerald-400 animate-pulse font-mono text-sm">Generando tráfico inicial...</div>}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};
export default App;

import React, { useState, useRef, useEffect } from 'react';
import { Aircraft, RadioMessage, Airport, PendingUpdates } from '../types';

interface ControlPanelProps {
  aircraft: Aircraft | null;
  airport: Airport | null;
  pendingUpdates: PendingUpdates; // Received from parent
  setPendingUpdates: (updates: PendingUpdates) => void; // Update parent
  radioHistory: RadioMessage[];
  onSendCommand: (text: string) => void;
  isProcessingRadio: boolean;
  // Voice Settings
  availableVoices: SpeechSynthesisVoice[];
  currentVoiceURI: string | null;
  onVoiceChange: (voiceURI: string) => void;
  onPlayTransmitSound?: () => void;
}

// Mapeo de códigos ICAO a fraseología de radio
const AIRLINE_NAMES: Record<string, string> = {
  'AMX': 'Aeroméxico',
  'VOI': 'Volaris',
  'VIV': 'Viva Aerobus',
  'DAL': 'Delta',
  'UAL': 'United',
  'AAL': 'American',
  'CMP': 'Copa',
  'AVA': 'Avianca',
  'IBE': 'Iberia',
  'LRC': 'Lacsa',
  'KLM': 'KLM',
  'AFR': 'Air France',
  'DLH': 'Lufthansa',
  'JBU': 'JetBlue',
  'SLI': 'Costera',
  'GMT': 'Magnicharters',
  'TAO': 'Aeromar'
};

const getSpokenCallsign = (callsign: string) => {
  const code = callsign.substring(0, 3).toUpperCase();
  const number = callsign.substring(3);
  const name = AIRLINE_NAMES[code] || code.split('').join(' '); 
  return `${name} ${number}`;
};

const ControlPanel: React.FC<ControlPanelProps> = ({ 
  aircraft, 
  airport,
  pendingUpdates,
  setPendingUpdates,
  radioHistory, 
  onSendCommand,
  isProcessingRadio,
  availableVoices,
  currentVoiceURI,
  onVoiceChange,
  onPlayTransmitSound
}) => {
  const [inputText, setInputText] = useState('');
  const [isListening, setIsListening] = useState(false);
  const [showWaypoints, setShowWaypoints] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const chatEndRef = useRef<HTMLDivElement>(null);

  // Mobile Tabs State
  const [activeTab, setActiveTab] = useState<'controls' | 'radio'>('controls');
  const [unreadCount, setUnreadCount] = useState(0);

  useEffect(() => {
    // Only scroll if we are near bottom or it's a new message
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });

    // Increment unread count if we are not on the radio tab
    if (activeTab !== 'radio' && radioHistory.length > 0) {
        setUnreadCount(prev => prev + 1);
    }
  }, [radioHistory]);

  // Reset count when switching to radio
  useEffect(() => {
    if (activeTab === 'radio') {
        setUnreadCount(0);
    }
  }, [activeTab]);

  // Determine if there are unsent changes
  const hasChanges = aircraft && (
    (pendingUpdates.heading !== null && pendingUpdates.heading !== Math.round(aircraft.targetHeading)) ||
    (pendingUpdates.altitude !== null && pendingUpdates.altitude !== Math.round(aircraft.targetAltitude)) ||
    (pendingUpdates.speed !== null && pendingUpdates.speed !== Math.round(aircraft.targetSpeed)) ||
    (pendingUpdates.clearedForILS !== aircraft.clearedForILS) ||
    (pendingUpdates.directTo !== null)
  );

  const handleAltitudeChange = (delta: number) => {
    if (!aircraft) return;
    const currentPending = pendingUpdates.altitude ?? Math.round(aircraft.targetAltitude);
    const newAlt = Math.max(0, Math.min(40000, currentPending + delta));

    setPendingUpdates({
        ...pendingUpdates,
        altitude: newAlt,
        clearedForILS: false // Disarm ILS if manually changing altitude
    });
  };

  const handleSpeedChange = (delta: number) => {
    if (!aircraft) return;
    const currentPending = pendingUpdates.speed ?? Math.round(aircraft.targetSpeed);
    const newSpd = Math.max(100, Math.min(600, currentPending + delta));

    setPendingUpdates({
        ...pendingUpdates,
        speed: newSpd
    });
  };

  const handleHeadingChange = (delta: number) => {
    if (!aircraft) return;
    const currentPending = pendingUpdates.heading ?? Math.round(aircraft.targetHeading);
    let newHdg = (currentPending + delta) % 360;
    if (newHdg < 0) newHdg += 360;

    setPendingUpdates({
        ...pendingUpdates,
        heading: newHdg,
        directTo: null, // Cancel direct to if manual heading
        clearedForILS: false // Disarm ILS if manually changing heading
    });
  };

  const handleDirectToSelect = (wpName: string) => {
    setPendingUpdates({
        ...pendingUpdates,
        directTo: wpName,
        clearedForILS: false
    });
    setShowWaypoints(false);
  };

  const toggleILS = () => {
    if (!aircraft) return;
    setPendingUpdates({
        ...pendingUpdates,
        clearedForILS: !pendingUpdates.clearedForILS
    });
  };

  const handleTransmit = () => {
    if (!aircraft || !hasChanges) return;

    // Build the command string based on changes
    const parts = [];

    // Heading / Navigation
    if (pendingUpdates.directTo) {
        parts.push(`directo a ${pendingUpdates.directTo}`);
    } else if (pendingUpdates.heading !== null && pendingUpdates.heading !== Math.round(aircraft.targetHeading)) {
        // Determine turn direction for realism
        let diff = pendingUpdates.heading - aircraft.heading;
        if (diff < -180) diff += 360;
        if (diff > 180) diff -= 360;
        const direction = diff > 0 ? "derecha" : "izquierda";
        parts.push(`vire ${direction} rumbo ${pendingUpdates.heading}`);
    }

    // Altitude
    if (pendingUpdates.altitude !== null && pendingUpdates.altitude !== Math.round(aircraft.targetAltitude)) {
        if (pendingUpdates.altitude > aircraft.altitude) parts.push(`ascienda nivel ${pendingUpdates.altitude}`);
        else parts.push(`descienda nivel ${pendingUpdates.altitude}`);
    }

    // Speed
    if (pendingUpdates.speed !== null && pendingUpdates.speed !== Math.round(aircraft.targetSpeed)) {
        parts.push(`reduzca velocidad a ${pendingUpdates.speed} nudos`);
    }

    // ILS
    if (pendingUpdates.clearedForILS !== aircraft.clearedForILS) {
        if (pendingUpdates.clearedForILS) parts.push(`autorizado para aterrizar ILS pista ${airport?.runwayName || 'activa'}`);
        else parts.push(`cancele aproximación ILS`);
    }

    if (parts.length === 0) return;

    const spokenCallsign = getSpokenCallsign(aircraft.callsign);
    const commandText = `${spokenCallsign}, ${parts.join(', ')}`;

    onPlayTransmitSound?.(); // Play sound effect
    onSendCommand(commandText);
  };

  const handleSubmitText = (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputText.trim() || !aircraft) return;

    let finalMsg = inputText;
    const spokenCallsign = getSpokenCallsign(aircraft.callsign);
    const rawCallsign = aircraft.callsign;

    const lowerInput = finalMsg.toLowerCase();
    if (!lowerInput.startsWith(spokenCallsign.toLowerCase()) && 
        !lowerInput.startsWith(rawCallsign.toLowerCase())) {
        finalMsg = `${spokenCallsign}, ${finalMsg}`;
    }

    onPlayTransmitSound?.(); // Play sound effect
    onSendCommand(finalMsg);
    setInputText('');
  };

  const toggleMic = () => {
    if (isListening) return;
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) {
      alert("Tu navegador no soporta reconocimiento de voz nativo.");
      return;
    }
    const recognition = new SpeechRecognition();
    recognition.lang = 'es-MX';
    recognition.start();
    setIsListening(true);
    recognition.onresult = (event: any) => setInputText(event.results[0][0].transcript);
    recognition.onend = () => setIsListening(false);
  };

  if (!aircraft) {
    return (
      <div className="h-full flex items-center justify-center text-slate-500 font-mono text-sm uppercase tracking-widest border-t border-slate-700 bg-slate-900">
        Seleccione una aeronave
      </div>
    );
  }

  // Display values (Pending takes precedence over actual target)
  const displayHeading = pendingUpdates.heading ?? Math.round(aircraft.targetHeading);
  const displayAltitude = pendingUpdates.altitude ?? Math.round(aircraft.targetAltitude);
  const displaySpeed = pendingUpdates.speed ?? Math.round(aircraft.targetSpeed);

  return (
    <div className="h-full bg-slate-900 border-t border-slate-700 p-2 font-mono text-slate-200 grid grid-cols-1 lg:grid-cols-3 gap-2 flex flex-col lg:grid overflow-hidden">

      {/* MOBILE TABS (Visible only on small screens) */}
      <div className="flex lg:hidden gap-1 mb-1 shrink-0">
          <button 
            onClick={() => setActiveTab('controls')}
            className={`flex-1 py-1 text-xs font-bold rounded uppercase border ${activeTab === 'controls' ? 'bg-slate-700 border-slate-500 text-white' : 'bg-slate-900 border-slate-800 text-slate-500'}`}
          >
              Controles
          </button>
          <button 
            onClick={() => setActiveTab('radio')}
            className={`flex-1 py-1 text-xs font-bold rounded uppercase border relative ${activeTab === 'radio' ? 'bg-slate-700 border-slate-500 text-white' : 'bg-slate-900 border-slate-800 text-slate-500'}`}
          >
              Radio
              {unreadCount > 0 && (
                  <span className="absolute -top-1 -right-1 w-3 h-3 bg-red-500 rounded-full animate-ping"></span>
              )}
              {unreadCount > 0 && (
                  <span className="absolute -top-1 -right-1 w-3 h-3 bg-red-500 rounded-full flex items-center justify-center text-[8px] text-white">
                      {unreadCount}
                  </span>
              )}
          </button>
      </div>

      {/* LEFT: Physical Controls */}
      <div className={`lg:col-span-2 grid-cols-3 gap-2 bg-slate-800/50 p-2 rounded border border-slate-700 relative 
        ${activeTab === 'controls' ? 'grid' : 'hidden'} lg:grid overflow-y-auto`}
      >

        {/* Info Header */}
        <div className="col-span-3 flex justify-between items-center border-b border-slate-700 pb-2 mb-2">
            <div>
                <span className="text-xl font-bold text-yellow-400 mr-2">{aircraft.callsign}</span>
                <span className="text-xs text-slate-400">{aircraft.model}</span>
                {aircraft.establishedOnILS && <span className="ml-2 px-2 py-0.5 bg-cyan-900 text-cyan-300 text-[10px] rounded border border-cyan-700">LOC CAPTURED</span>}
            </div>
            <div className="text-xs text-slate-300 flex gap-4">
                <span className="text-slate-400">ACTUAL:</span>
                <span>HDG: {Math.floor(aircraft.heading)}°</span>
                <span>ALT: {Math.floor(aircraft.altitude)}</span>
                <span>SPD: {Math.floor(aircraft.speed)}</span>
            </div>
        </div>

        {/* Heading Control */}
        <div className="flex flex-col items-center border-r border-slate-700 px-2 relative">
          <label className="text-[10px] text-slate-400 mb-1">RUMBO (HDG)</label>
          <div className="flex items-center gap-1">
            <button onClick={() => handleHeadingChange(-10)} className="bg-slate-700 hover:bg-slate-600 p-1 rounded min-w-[30px] text-xs">-10</button>
            <div className={`text-lg font-bold w-16 text-center transition-colors 
                ${pendingUpdates.directTo ? 'text-sky-400 text-xs' : displayHeading !== Math.round(aircraft.targetHeading) ? 'text-yellow-400 animate-pulse' : 'text-emerald-400'}`}>
                {pendingUpdates.directTo ? pendingUpdates.directTo : pendingUpdates.clearedForILS && aircraft.establishedOnILS ? 'ILS' : displayHeading + '°'}
            </div>
            <button onClick={() => handleHeadingChange(10)} className="bg-slate-700 hover:bg-slate-600 p-1 rounded min-w-[30px] text-xs">+10</button>
          </div>
          <div className="flex gap-1 mt-1">
              <button onClick={() => setShowWaypoints(!showWaypoints)} className="text-[9px] bg-sky-800 text-sky-200 px-2 py-0.5 rounded border border-sky-600 hover:bg-sky-700">DIRECTO</button>
          </div>

          {showWaypoints && airport && (
              <div className="absolute bottom-full left-0 w-full bg-slate-800 border border-slate-600 rounded shadow-xl max-h-48 overflow-y-auto z-50">
                  {airport.waypoints.map(wp => (
                      <button 
                        key={wp.name} 
                        onClick={() => handleDirectToSelect(wp.name)}
                        className="w-full text-left px-2 py-1 text-xs hover:bg-slate-700 border-b border-slate-700/50 flex justify-between"
                      >
                          <span className="font-bold text-sky-400">{wp.name}</span>
                          <span className="text-[8px] text-slate-500">{wp.type}</span>
                      </button>
                  ))}
              </div>
          )}
        </div>

        {/* Altitude Control */}
        <div className="flex flex-col items-center border-r border-slate-700 px-2">
          <label className="text-[10px] text-slate-400 mb-1">ALTITUD</label>
          <div className="flex items-center gap-1">
            <button onClick={() => handleAltitudeChange(-1000)} className="bg-slate-700 hover:bg-slate-600 p-1 rounded min-w-[30px] text-xs">-1k</button>
            <div className={`text-lg font-bold w-16 text-center transition-colors
                ${displayAltitude !== Math.round(aircraft.targetAltitude) ? 'text-yellow-400 animate-pulse' : 'text-emerald-400'}`}>
                {pendingUpdates.clearedForILS && aircraft.establishedOnILS ? 'GS' : displayAltitude}
            </div>
            <button onClick={() => handleAltitudeChange(1000)} className="bg-slate-700 hover:bg-slate-600 p-1 rounded min-w-[30px] text-xs">+1k</button>
          </div>
          <button onClick={() => handleAltitudeChange(-100)} className="mt-1 text-[9px] bg-slate-800 px-2 py-0.5 rounded border border-slate-600">Ajuste Fino (-100)</button>
        </div>

        {/* Speed / ILS Control */}
        <div className="flex flex-col items-center px-2">
          <label className="text-[10px] text-slate-400 mb-1">VELOCIDAD</label>
          <div className="flex items-center gap-1">
            <button onClick={() => handleSpeedChange(-20)} className="bg-slate-700 hover:bg-slate-600 p-1 rounded min-w-[30px] text-xs">-20</button>
            <div className={`text-lg font-bold w-12 text-center transition-colors
                ${displaySpeed !== Math.round(aircraft.targetSpeed) ? 'text-yellow-400 animate-pulse' : 'text-emerald-400'}`}>
                {displaySpeed}
            </div>
            <button onClick={() => handleSpeedChange(20)} className="bg-slate-700 hover:bg-slate-600 p-1 rounded min-w-[30px] text-xs">+20</button>
          </div>

          <button 
                onClick={toggleILS}
                className={`mt-2 w-full text-[10px] px-2 py-1 rounded font-bold uppercase border transition-all ${
                    aircraft.establishedOnILS 
                    ? 'bg-cyan-600 text-white border-cyan-400 shadow-[0_0_10px_rgba(6,182,212,0.5)]'
                    : pendingUpdates.clearedForILS
                        ? 'bg-yellow-600 text-white border-yellow-400 animate-pulse'
                        : 'bg-slate-700 text-slate-400 border-slate-600 hover:bg-slate-600'
                }`}
            >
                {aircraft.establishedOnILS ? 'ILS LOCKED' : pendingUpdates.clearedForILS ? 'ILS ARMADO' : 'ILS APP'}
          </button>
        </div>

        {/* Transmit Button Overlay/Section */}
        <div className="col-span-3 mt-1 flex justify-end">
            <button 
                onClick={handleTransmit}
                disabled={!hasChanges || isProcessingRadio}
                className={`w-full py-2 rounded font-bold tracking-widest transition-all
                    ${!hasChanges 
                        ? 'bg-slate-800 text-slate-600 border border-slate-700 cursor-not-allowed' 
                        : isProcessingRadio
                            ? 'bg-emerald-900 text-emerald-500 border border-emerald-700 animate-pulse cursor-wait'
                            : 'bg-emerald-600 text-white hover:bg-emerald-500 border border-emerald-400 shadow-[0_0_15px_rgba(16,185,129,0.4)]'
                    }`}
            >
                {isProcessingRadio ? 'TRANSMITIENDO...' : hasChanges ? 'TRANSMITIR COMANDOS' : 'TRANSMITIR COMANDOS'}
            </button>
        </div>
      </div>

      {/* RIGHT: Radio / Communication */}
      <div className={`flex flex-col bg-black rounded border border-slate-700 overflow-hidden relative lg:block 
        ${activeTab === 'radio' ? 'flex-1 h-full' : 'hidden'}`}
      >
        {/* Header */}
        <div className="bg-slate-800 px-2 py-1 text-[10px] font-bold text-slate-400 flex justify-between items-center shrink-0">
            <span>FRECUENCIA 118.1</span>
            <div className="flex gap-2">
                 {isProcessingRadio && <span className="text-emerald-400 animate-pulse">TX...</span>}
                 <button onClick={() => setShowSettings(!showSettings)} className="hover:text-white" title="Configuración de Voz">
                    ⚙️
                 </button>
            </div>
        </div>

        {/* Voice Settings Popover */}
        {showSettings && (
            <div className="absolute top-7 right-2 left-2 z-50 bg-slate-800 border border-slate-600 rounded shadow-xl p-2 text-xs">
                <div className="flex justify-between items-center mb-1">
                    <span className="font-bold text-slate-300">Voz ATC / Sistema</span>
                    <button onClick={() => setShowSettings(false)} className="text-slate-500 hover:text-white">✕</button>
                </div>
                <select 
                    value={currentVoiceURI || ''}
                    onChange={(e) => onVoiceChange(e.target.value)}
                    className="w-full bg-black border border-slate-600 rounded p-1 text-slate-200 focus:outline-none"
                >
                    {availableVoices.length === 0 && <option value="">Por defecto (Sistema)</option>}
                    {availableVoices.map(v => (
                        <option key={v.voiceURI} value={v.voiceURI}>
                            {v.name} ({v.lang})
                        </option>
                    ))}
                </select>
                <div className="mt-2 text-[10px] text-slate-500 italic">
                    * Los pilotos tendrán voces aleatorias.
                </div>
            </div>
        )}

        {/* Messages Log (Scrollable, takes remaining space) */}
        <div className="flex-1 overflow-y-auto p-2 space-y-2 text-xs font-mono min-h-0 bg-black/50">
          {radioHistory.length === 0 && (
            <div className="text-slate-600 italic text-center mt-4">Canal libre.</div>
          )}
          {radioHistory.map((msg) => (
            <div key={msg.id} className={`flex flex-col ${msg.sender === 'ATC' ? 'items-end' : 'items-start'}`}>
              <div className={`px-2 py-1 rounded max-w-[90%] ${
                msg.sender === 'ATC' ? 'bg-sky-900/40 text-sky-200 border border-sky-800' : 'bg-emerald-900/40 text-emerald-200 border border-emerald-800'
              }`}>
                <span className="font-bold mr-1 text-[10px] opacity-70 block">
                  {msg.sender === 'ATC' ? 'TWR' : msg.callsign}:
                </span>
                {msg.text}
              </div>
            </div>
          ))}
          <div ref={chatEndRef} />
        </div>

        {/* Input Area (Static at bottom) */}
        <form onSubmit={handleSubmitText} className="p-1 bg-slate-900 border-t border-slate-800 flex gap-1 shrink-0 z-10 relative">
          <button 
            type="button" 
            onClick={toggleMic}
            className={`p-2 rounded transition-colors ${isListening ? 'bg-red-600 text-white animate-pulse' : 'bg-slate-800 text-slate-400 hover:text-white'}`}
          >
            <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" className="w-4 h-4">
              <path d="M8.25 4.5a3.75 3.75 0 117.5 0v8.25a3.75 3.75 0 11-7.5 0V4.5z" />
              <path d="M6 10.5a.75.75 0 01.75.75v1.5a5.25 5.25 0 1010.5 0v-1.5a.75.75 0 011.5 0v1.5a6.751 6.751 0 01-6 6.709v2.291h3a.75.75 0 010 1.5h-7.5a.75.75 0 010-1.5h3v-2.291a6.751 6.751 0 01-6-6.709v-1.5A.75.75 0 016 10.5z" />
            </svg>
          </button>
          <input 
            type="text" 
            value={inputText}
            onChange={(e) => setInputText(e.target.value)}
            className="flex-1 bg-black border border-slate-700 rounded px-2 text-sm text-green-400 font-mono focus:outline-none focus:border-green-500 placeholder-slate-700"
            placeholder="Instrucciones manuales..." 
            disabled={isProcessingRadio}
          />
          <button 
            type="submit" 
            className="bg-emerald-700 hover:bg-emerald-600 text-white px-3 py-1 rounded text-xs font-bold transition-colors disabled:opacity-50"
            disabled={isProcessingRadio || !inputText.trim()}
          >
            ENV
          </button>
        </form>
      </div>
    </div>
  );
};

export default ControlPanel;

import React, { useEffect, useState, useRef } from 'react';
import { Aircraft, Airport, FlightStatus, PendingUpdates, Coordinates } from '../types';

interface RadarScreenProps {
  aircraft: Aircraft[];
  airport: Airport;
  selectedAircraftId: string | null;
  onSelectAircraft: (id: string | null) => void;
  pendingUpdates: PendingUpdates | null;
  onRadarInteraction: (updates: { heading?: number | null, directTo?: string | null }) => void;
  weatherSeverity: number; 
  score: number; 
  gameTier: number; // For alternates
  ashCloud?: { points: Coordinates[], maxAltitude: number } | null;
}

const TURN_RATE_PER_TICK = 0.60; 
const SIM_SPEED_FACTOR = 1.0; 

const RadarScreen: React.FC<RadarScreenProps> = ({ 
  aircraft, 
  airport, 
  selectedAircraftId, 
  onSelectAircraft,
  pendingUpdates,
  onRadarInteraction,
  weatherSeverity,
  score,
  gameTier,
  ashCloud
}) => {
  const [sweepAngle, setSweepAngle] = useState(0);
  const [mapOpacity, setMapOpacity] = useState(0.4);
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const mapInstanceRef = useRef<any>(null);
  const tileLayerRef = useRef<any>(null); 
  const weatherLayerRef = useRef<any>(null); 
  const markersRef = useRef<{[key: string]: any}>({}); 
  const ilsLayerRef = useRef<any>(null); 
  const captureZoneLayerRef = useRef<any>(null); 
  const coverageLayerRef = useRef<any>(null); 
  const ashLayerRef = useRef<any>(null);
  const alternateLayerRef = useRef<any>(null);
  const [projectionVersion, setProjectionVersion] = useState(0); 
  const [radarPixelRadius, setRadarPixelRadius] = useState(600); 
  const [mapSize, setMapSize] = useState({ w: window.innerWidth, h: window.innerHeight });

  const [isDragging, setIsDragging] = useState(false);
  const [dragStartPos, setDragStartPos] = useState<{x: number, y: number} | null>(null);
  const [dragCurrentPos, setDragCurrentPos] = useState<{x: number, y: number} | null>(null);
  const [dragHeading, setDragHeading] = useState<number | null>(null);
  const [snappedWaypoint, setSnappedWaypoint] = useState<string | null>(null);

  const selectedPlane = aircraft.find(p => p.id === selectedAircraftId);
  const isSelectedPlaneEstablished = selectedPlane?.establishedOnILS;

  useEffect(() => {
      const handleResize = () => setMapSize({ w: window.innerWidth, h: window.innerHeight });
      window.addEventListener('resize', handleResize);
      return () => window.removeEventListener('resize', handleResize);
  }, []);

  useEffect(() => {
    if (!mapContainerRef.current) return;
    if (!mapInstanceRef.current) {
        // @ts-ignore
        const map = window.L.map(mapContainerRef.current, {
            center: [airport.location.lat, airport.location.lon],
            zoom: airport.initialZoom,
            zoomControl: false,
            attributionControl: false,
            boxZoom: false,
            doubleClickZoom: false,
            dragging: true,
            scrollWheelZoom: true,
            touchZoom: true,
            minZoom: 6, // Evita zoom excesivo hacia afuera
            maxZoom: 16 // Evita zoom excesivo hacia adentro (tiles grises)
        });

        // @ts-ignore
        const tileLayer = window.L.tileLayer('https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png', {
            attribution: '&copy; OpenStreetMap &copy; CARTO',
            subdomains: 'abcd',
            maxZoom: 20,
            opacity: mapOpacity 
        }).addTo(map);

        mapInstanceRef.current = map;
        tileLayerRef.current = tileLayer;

        map.on('move', () => setProjectionVersion(v => v + 1));
        map.on('zoom', () => setProjectionVersion(v => v + 1));
        map.on('click', () => { onSelectAircraft(null); });
    } else {
        mapInstanceRef.current.setView([airport.location.lat, airport.location.lon], airport.initialZoom);
    }
  }, [airport, onSelectAircraft]);

  useEffect(() => {
      if (!mapInstanceRef.current) return;
      const fetchWeather = async () => {
          try {
              const response = await fetch('https://api.rainviewer.com/public/weather-maps.json');
              const data = await response.json();
              if (data && data.radar && data.radar.past && data.radar.past.length > 0) {
                  const lastPast = data.radar.past[data.radar.past.length - 1];
                  const time = lastPast.time;
                  const host = data.host; 
                  const url = `${host}${time}/256/{z}/{x}/{y}/2/1_1.png`;
                  if (weatherLayerRef.current) weatherLayerRef.current.remove();
                  // @ts-ignore
                  weatherLayerRef.current = window.L.tileLayer(url, { opacity: 0, zIndex: 10 }).addTo(mapInstanceRef.current);
              }
          } catch (e) { console.warn("RainViewer failed", e); }
      };
      fetchWeather();
      const interval = setInterval(fetchWeather, 600000);
      return () => clearInterval(interval);
  }, []);

  useEffect(() => {
      if (weatherLayerRef.current) weatherLayerRef.current.setOpacity(weatherSeverity * 0.6);
  }, [weatherSeverity]);

  useEffect(() => {
    if (!mapInstanceRef.current) return;
    const map = mapInstanceRef.current;
    const updateRadarSize = () => {
        const centerLatLng = [airport.location.lat, airport.location.lon];
        const edgeLatLng = [airport.location.lat + 1.8, airport.location.lon]; 
        // @ts-ignore
        const p1 = map.latLngToContainerPoint(centerLatLng);
        // @ts-ignore
        const p2 = map.latLngToContainerPoint(edgeLatLng);
        setRadarPixelRadius(Math.abs(p1.y - p2.y));
    };
    updateRadarSize();
    map.on('zoomend', updateRadarSize);
    return () => { map.off('zoomend', updateRadarSize); };
  }, [airport, projectionVersion]); 

  useEffect(() => {
    if (!mapInstanceRef.current) return;
    if (coverageLayerRef.current) coverageLayerRef.current.remove();
    // @ts-ignore
    coverageLayerRef.current = window.L.circle([airport.location.lat, airport.location.lon], {
        radius: 200000,
        color: '#475569', 
        weight: 1,
        dashArray: '4, 8',
        fill: false,
        opacity: 0.5,
        interactive: false
    }).addTo(mapInstanceRef.current);

    // Add Volcano Marker for Popocatepetl if MMMX
    if (airport.code === 'MMMX') {
         // @ts-ignore
         window.L.marker([19.0228, -98.6278], {
             // @ts-ignore
             icon: window.L.divIcon({
                 className: 'bg-transparent',
                 html: '<div class="text-xl">🌋</div>',
                 iconSize: [20, 20]
             })
         }).addTo(mapInstanceRef.current);
    }

    return () => { if (coverageLayerRef.current) coverageLayerRef.current.remove(); };
  }, [airport]);

  // Ash Cloud Rendering
  useEffect(() => {
      if (!mapInstanceRef.current) return;
      if (ashLayerRef.current) ashLayerRef.current.remove();

      if (ashCloud) {
          const latlngs = ashCloud.points.map(p => [p.lat, p.lon]);
          // @ts-ignore
          ashLayerRef.current = window.L.polygon(latlngs, {
              color: '#71717a', // Zinc 500
              fillColor: '#52525b', // Zinc 600
              fillOpacity: 0.4,
              weight: 0,
              className: 'animate-pulse'
          }).addTo(mapInstanceRef.current);
      }
      return () => { if (ashLayerRef.current) ashLayerRef.current.remove(); };
  }, [ashCloud]);

  // Alternate Airports (Level 1+)
  useEffect(() => {
      if (!mapInstanceRef.current) return;
      if (alternateLayerRef.current) alternateLayerRef.current.clearLayers();
      else // @ts-ignore 
           alternateLayerRef.current = window.L.layerGroup().addTo(mapInstanceRef.current);

      if (gameTier >= 1 && airport.alternates) {
           airport.alternates.forEach(alt => {
               // Marker
               // @ts-ignore
               window.L.marker([alt.location.lat, alt.location.lon], {
                   // @ts-ignore
                   icon: window.L.divIcon({
                       className: 'bg-transparent',
                       html: `<div class="w-2 h-2 bg-slate-400 border border-slate-200"></div><div class="text-[9px] text-slate-400 font-mono mt-1">${alt.code}</div>`,
                       iconSize: [30, 30]
                   })
               }).addTo(alternateLayerRef.current);

               // ILS Line for alternate
               const localizerAngle = (alt.runwayHeading + 180) % 360;
               const endLat = alt.location.lat + (alt.ilsLengthNM / 60) * Math.cos(localizerAngle * Math.PI / 180);
               const endLon = alt.location.lon + (alt.ilsLengthNM / 60) * Math.sin(localizerAngle * Math.PI / 180) / Math.cos(alt.location.lat * Math.PI / 180);

               // @ts-ignore
               window.L.polyline([[alt.location.lat, alt.location.lon], [endLat, endLon]], {
                   color: '#3b82f6',
                   weight: 2,
                   opacity: 0.5,
                   dashArray: '5,5'
               }).addTo(alternateLayerRef.current);
           });
      }
  }, [gameTier, airport]);

  useEffect(() => {
    if (tileLayerRef.current) tileLayerRef.current.setOpacity(mapOpacity);
  }, [mapOpacity]);

  useEffect(() => {
    if (!mapInstanceRef.current) return;
    const map = mapInstanceRef.current;
    Object.values(markersRef.current).forEach((marker: any) => map.removeLayer(marker));
    markersRef.current = {};
    airport.waypoints.forEach(wp => {
        const isSnapped = snappedWaypoint === wp.name || (pendingUpdates?.directTo === wp.name && selectedAircraftId !== null);
        const icon = createWaypointIcon(wp, isSnapped);
        // @ts-ignore
        const marker = window.L.marker([wp.location.lat, wp.location.lon], { icon, interactive: false }).addTo(map);
        markersRef.current[wp.name] = marker;
    });
    return () => { Object.values(markersRef.current).forEach((marker: any) => map.removeLayer(marker)); };
  }, [airport.waypoints]); 

  useEffect(() => {
      airport.waypoints.forEach(wp => {
          const marker = markersRef.current[wp.name];
          if (marker) {
              const isSnapped = snappedWaypoint === wp.name || (pendingUpdates?.directTo === wp.name && selectedAircraftId !== null);
              const newIcon = createWaypointIcon(wp, isSnapped);
              marker.setIcon(newIcon);
          }
      });
  }, [snappedWaypoint, pendingUpdates?.directTo, selectedAircraftId]);

  useEffect(() => {
    if (!mapInstanceRef.current) return;
    const localizerAngle = (airport.runwayHeading + 180) % 360;
    const ILS_LENGTH_NM = 18;
    const projectPoint = (lat: number, lon: number, brng: number, distNM: number) => {
        const R = 3440.065; 
        const d = distNM / R;
        const brngRad = brng * Math.PI / 180;
        const latRad = lat * Math.PI / 180;
        const lonRad = lon * Math.PI / 180;
        const lat2 = Math.asin(Math.sin(latRad) * Math.cos(d) + Math.cos(latRad) * Math.sin(d) * Math.cos(brngRad));
        const lon2 = lonRad + Math.atan2(Math.sin(brngRad) * Math.sin(d) * Math.cos(latRad), Math.cos(d) - Math.sin(latRad) * Math.sin(lat2));
        return [lat2 * 180 / Math.PI, lon2 * 180 / Math.PI];
    };

    const startCoords = [airport.location.lat, airport.location.lon];
    const endCoords = projectPoint(airport.location.lat, airport.location.lon, localizerAngle, ILS_LENGTH_NM);

    if (ilsLayerRef.current) {
        ilsLayerRef.current.setLatLngs([startCoords, endCoords]);
    } else {
        // @ts-ignore
        ilsLayerRef.current = window.L.polyline([startCoords, endCoords], {
            weight: 5,
            opacity: 1.0,
            color: '#3b82f6', 
            lineCap: 'butt'
        }).addTo(mapInstanceRef.current);
    }

    if (score < 10) {
        if (!captureZoneLayerRef.current) // @ts-ignore
             captureZoneLayerRef.current = window.L.layerGroup().addTo(mapInstanceRef.current);
        else captureZoneLayerRef.current.clearLayers();

        const leftLimit = (localizerAngle - 15 + 360) % 360;
        const rightLimit = (localizerAngle + 15) % 360;
        const leftEnd = projectPoint(airport.location.lat, airport.location.lon, leftLimit, ILS_LENGTH_NM - 3);
        const rightEnd = projectPoint(airport.location.lat, airport.location.lon, rightLimit, ILS_LENGTH_NM - 3);
        // @ts-ignore
        window.L.polyline([startCoords, leftEnd], { color: '#fbbf24', dashArray: '10, 10', weight: 2, opacity: 0.6 }).addTo(captureZoneLayerRef.current);
        // @ts-ignore
        window.L.polyline([startCoords, rightEnd], { color: '#fbbf24', dashArray: '10, 10', weight: 2, opacity: 0.6 }).addTo(captureZoneLayerRef.current);
        const labelPos = projectPoint(airport.location.lat, airport.location.lon, localizerAngle, ILS_LENGTH_NM - 5);
        // @ts-ignore
        window.L.marker(labelPos, { icon: window.L.divIcon({ className: 'bg-transparent', html: '<div class="text-[#fbbf24] text-[10px] font-mono opacity-60 -rotate-90 whitespace-nowrap">ZONA DE CAPTURA ILS</div>', iconSize: [100, 20] }) }).addTo(captureZoneLayerRef.current);
    } else {
        if (captureZoneLayerRef.current) captureZoneLayerRef.current.clearLayers();
    }
    return () => { if (ilsLayerRef.current) { ilsLayerRef.current.remove(); ilsLayerRef.current = null; } if (captureZoneLayerRef.current) captureZoneLayerRef.current.clearLayers(); };
  }, [airport, score]);

  useEffect(() => {
    if (ilsLayerRef.current) {
        if (isSelectedPlaneEstablished) ilsLayerRef.current.setStyle({ color: '#10b981', opacity: 1, weight: 6 });
        else ilsLayerRef.current.setStyle({ color: '#3b82f6', opacity: 1.0, weight: 5 });
    }
  }, [isSelectedPlaneEstablished]);

  const createWaypointIcon = (wp: any, isSnapped: boolean) => {
      // @ts-ignore
      return window.L.divIcon({
          className: 'bg-transparent border-none',
          html: `
            <div class="relative flex flex-col items-center justify-center transition-all duration-200 ${isSnapped ? 'scale-125 z-50' : ''}">
                ${isSnapped ? '<div class="absolute w-12 h-12 rounded-full border-2 border-cyan-400 animate-pulse bg-cyan-900/30 left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2"></div>' : ''}
                ${wp.type === 'VOR' ? 
                    `<svg width="18" height="18" viewBox="0 0 24 24" class="${isSnapped ? 'text-cyan-400' : 'text-slate-400'} stroke-current stroke-[2px] fill-slate-900/50"><path d="M12 2l8.66 5v10L12 22l-8.66-5V7L12 2z" /><circle cx="12" cy="12" r="2" class="fill-current" /></svg>` : 
                 wp.type === 'FIX' ? 
                    `<svg width="10" height="10" viewBox="0 0 24 24" class="${isSnapped ? 'text-cyan-400' : 'text-slate-600'} fill-current opacity-80"><path d="M12 4L4 20h16z" /></svg>` :
                    `<div class="w-4 h-4 border-2 border-slate-300 bg-slate-900/30"></div>`
                }
                <div class="mt-1 text-[10px] font-mono font-bold whitespace-nowrap tracking-wider drop-shadow-md ${isSnapped ? 'text-cyan-300 scale-110' : 'text-slate-400'}">${wp.name}</div>
            </div>
          `,
          iconSize: [40, 40],
          iconAnchor: [20, 20] 
      });
  };

  useEffect(() => {
    const interval = setInterval(() => { setSweepAngle((prev) => (prev + 1.5) % 360); }, 20);
    return () => clearInterval(interval);
  }, []);

  const project = (lat: number, lon: number) => {
      if (!mapInstanceRef.current) return { x: 0, y: 0 };
      // @ts-ignore
      const point = mapInstanceRef.current.latLngToContainerPoint([lat, lon]);
      return { x: point.x, y: point.y };
  };

  useEffect(() => {
      const handleGlobalMove = (e: MouseEvent | TouchEvent) => {
          if (!isDragging || !dragStartPos || !mapContainerRef.current) return;
          let clientX, clientY;
          if ('touches' in e) { clientX = (e as TouchEvent).touches[0].clientX; clientY = (e as TouchEvent).touches[0].clientY; } 
          else { clientX = (e as MouseEvent).clientX; clientY = (e as MouseEvent).clientY; }
          const rect = mapContainerRef.current.getBoundingClientRect();
          const x = clientX - rect.left;
          const y = clientY - rect.top;
          setDragCurrentPos({ x, y });
          let foundSnap = null;
          for (const wp of airport.waypoints) {
              const wpPos = project(wp.location.lat, wp.location.lon);
              const dist = Math.sqrt(Math.pow(x - wpPos.x, 2) + Math.pow(y - wpPos.y, 2));
              if (dist < 40) { foundSnap = wp.name; break; }
          }
          if (foundSnap) {
              setSnappedWaypoint(foundSnap);
              setDragHeading(null);
              onRadarInteraction({ directTo: foundSnap });
          } else {
              setSnappedWaypoint(null);
              const dx = x - dragStartPos.x;
              const dy = y - dragStartPos.y;
              const angleRad = Math.atan2(dy, dx);
              let angleDeg = angleRad * 180 / Math.PI;
              let compassHeading = (angleDeg + 90) % 360;
              if (compassHeading < 0) compassHeading += 360;
              const newHeading = Math.round(compassHeading);
              setDragHeading(newHeading);
              onRadarInteraction({ heading: newHeading });
          }
      };
      const handleGlobalUp = () => {
          if (isDragging) {
              setIsDragging(false);
              setDragStartPos(null);
              setDragCurrentPos(null);
              setDragHeading(null);
              setSnappedWaypoint(null);
          }
      };
      window.addEventListener('mousemove', handleGlobalMove);
      window.addEventListener('mouseup', handleGlobalUp);
      window.addEventListener('touchmove', handleGlobalMove, { passive: false });
      window.addEventListener('touchend', handleGlobalUp);
      return () => {
          window.removeEventListener('mousemove', handleGlobalMove);
          window.removeEventListener('mouseup', handleGlobalUp);
          window.removeEventListener('touchmove', handleGlobalMove);
          window.removeEventListener('touchend', handleGlobalUp);
      }
  }, [isDragging, dragStartPos, onRadarInteraction, airport.waypoints]);

  const centerPos = project(airport.location.lat, airport.location.lon);

  const handlePlaneStart = (e: React.MouseEvent | React.TouchEvent, planeId: string, pos: {x: number, y: number}) => {
      e.stopPropagation(); 
      onSelectAircraft(planeId);
      setIsDragging(true);
      setDragStartPos(pos);
      setDragCurrentPos(pos);
  };

  const calculatePath = (startLat: number, startLon: number, startHdg: number, targetHdg: number, speedKnots: number) => {
    const points: string[] = [];
    let currentLat = startLat;
    let currentLon = startLon;
    let currentHdg = startHdg;
    const tickDurationHours = 0.2 / 3600; 
    let limit = 1500; 
    for (let i = 0; i < limit; i++) {
        if (i % 10 === 0) { const p = project(currentLat, currentLon); points.push(`${p.x},${p.y}`); }
        let diff = targetHdg - currentHdg;
        if (diff < -180) diff += 360;
        if (diff > 180) diff -= 360;
        if (Math.abs(diff) < TURN_RATE_PER_TICK) currentHdg = targetHdg;
        else currentHdg += Math.sign(diff) * TURN_RATE_PER_TICK;
        currentHdg = (currentHdg + 360) % 360;
        const distNM = speedKnots * tickDurationHours * SIM_SPEED_FACTOR;
        const distDeg = distNM / 60;
        const radHdg = currentHdg * Math.PI / 180;
        const dLat = distDeg * Math.cos(radHdg);
        const dLon = distDeg * Math.sin(radHdg) / Math.cos(currentLat * Math.PI / 180);
        currentLat += dLat;
        currentLon += dLon;
        if (currentHdg === targetHdg) {
            const remainingTicks = 4000; 
            const finalDistNM = speedKnots * (remainingTicks * 0.2 / 3600);
            const finalDistDeg = finalDistNM / 60;
            const finalLat = currentLat + finalDistDeg * Math.cos(radHdg);
            const finalLon = currentLon + finalDistDeg * Math.sin(radHdg) / Math.cos(currentLat * Math.PI / 180);
            const pEnd = project(finalLat, finalLon);
            points.push(`${pEnd.x},${pEnd.y}`);
            break;
        }
    }
    return points.join(' ');
  };

  let directToLineCoords = null;
  let curvedPathPoints = null;

  if (selectedPlane) {
      if (pendingUpdates?.directTo) {
        const wp = airport.waypoints.find(w => w.name === pendingUpdates.directTo);
        if (wp) {
            const start = project(selectedPlane.position.lat, selectedPlane.position.lon);
            const end = project(wp.location.lat, wp.location.lon);
            directToLineCoords = { start, end };
        }
      } else if (pendingUpdates?.heading !== null || (isDragging && dragHeading !== null)) {
        const targetH = isDragging && dragHeading !== null ? dragHeading : (pendingUpdates?.heading !== null ? pendingUpdates.heading : null);
        if (targetH !== null && Math.abs(targetH - selectedPlane.heading) > 1) {
            curvedPathPoints = calculatePath(selectedPlane.position.lat, selectedPlane.position.lon, selectedPlane.heading, targetH, selectedPlane.speed);
        }
      }
  }

  return (
    <div className="relative w-full h-full bg-black overflow-hidden shadow-2xl rounded-lg border border-slate-800 cursor-crosshair touch-none">
      <div ref={mapContainerRef} className="absolute inset-0 z-0"></div>

      {/* Selector de Opacidad - Movido a esquina inferior izquierda */}
      <div className="absolute bottom-4 left-4 z-50 flex items-center gap-2 bg-slate-900/80 p-2 rounded border border-slate-700 pointer-events-auto">
        <span className="text-[9px] text-slate-400 font-mono">MAPA</span>
        <input type="range" min="0" max="1" step="0.1" value={mapOpacity} onChange={(e) => setMapOpacity(parseFloat(e.target.value))} className="w-16 h-1 bg-slate-700 rounded-lg appearance-none cursor-pointer" />
      </div>

      <div className="absolute bottom-4 right-4 z-50 flex flex-col gap-1 pointer-events-auto">
        <button className="w-8 h-8 bg-slate-800 text-slate-300 border border-slate-600 rounded hover:bg-slate-700 flex items-center justify-center font-bold" onClick={() => mapInstanceRef.current?.zoomIn()}>+</button>
        <button className="w-8 h-8 bg-slate-800 text-slate-300 border border-slate-600 rounded hover:bg-slate-700 flex items-center justify-center font-bold" onClick={() => mapInstanceRef.current?.zoomOut()}>-</button>
      </div>

      <div className="absolute inset-0 z-25 pointer-events-none overflow-hidden">
          <svg className="w-full h-full">
            {curvedPathPoints && !snappedWaypoint && (
                <polyline points={curvedPathPoints} fill="none" stroke="#facc15" strokeWidth="3" strokeDasharray="8,6" opacity="1" />
            )}
            {directToLineCoords && (
                <line x1={directToLineCoords.start.x} y1={directToLineCoords.start.y} x2={directToLineCoords.end.x} y2={directToLineCoords.end.y} stroke={snappedWaypoint ? "#22d3ee" : "#facc15"} strokeWidth="3" strokeDasharray={snappedWaypoint ? "0" : "8,6"} />
            )}
          </svg>
          {isDragging && dragCurrentPos && (
              <div className={`absolute rounded px-2 py-1 text-xs font-bold font-mono border ${snappedWaypoint ? 'bg-cyan-900/90 text-cyan-400 border-cyan-500' : 'bg-slate-900/80 text-yellow-400 border-yellow-500'}`} style={{ left: dragCurrentPos.x + 15, top: dragCurrentPos.y + 15 }}>{snappedWaypoint ? `DIRECTO A ${snappedWaypoint}` : `${dragHeading}°`}</div>
          )}
      </div>

      <div className="absolute inset-0 z-30 pointer-events-none">
          {aircraft.map((plane) => {
            if (plane.status === FlightStatus.LANDED || plane.status === FlightStatus.CRASHED) return null;
            const pos = project(plane.position.lat, plane.position.lon);
            const isSelected = plane.id === selectedAircraftId;
            const isEmergency = plane.status === FlightStatus.LOST_SEPARATION || plane.proximityAlert === 'CRITICAL';
            const isWarning = plane.proximityAlert === 'WARNING';
            const isOnILS = plane.establishedOnILS;
            const hasSquawk7700 = plane.squawk === '7700';
            let navLabel = null;
            let navColor = "text-emerald-400";

            if (hasSquawk7700) { navLabel = "SQ 7700"; navColor = "text-red-500 animate-pulse"; } 
            else if (plane.squawk === '7600') { navLabel = "SQ 7600"; navColor = "text-orange-500 animate-pulse"; } 
            else if (isSelected && pendingUpdates?.directTo) { navLabel = `→${pendingUpdates.directTo}`; navColor = "text-yellow-400"; } 
            else if (plane.currentDirectTo && !plane.clearedForILS) { navLabel = `→${plane.currentDirectTo}`; navColor = "text-orange-400"; } 
            else if (isOnILS) { navLabel = `LOC LOCK`; navColor = "text-cyan-400"; } 
            else if (plane.clearedForILS) { navLabel = `ILS ARM`; navColor = "text-blue-400"; } 
            else { navLabel = `H ${Math.round(plane.heading).toString().padStart(3,'0')}`; navColor = "text-slate-400"; }

            if (pos.x < -100 || pos.y < -100 || pos.x > window.innerWidth + 100 || pos.y > window.innerHeight + 100) return null;

            return (
              <React.Fragment key={plane.id}>
                {isSelected && plane.history && plane.history.map((histPos, idx) => {
                    const hPos = project(histPos.lat, histPos.lon);
                    return (<div key={idx} className="absolute w-[2px] h-[2px] bg-emerald-500/40 rounded-full pointer-events-none" style={{ left: hPos.x, top: hPos.y }} />);
                })}
                <div onMouseDown={(e) => handlePlaneStart(e, plane.id, pos)} onTouchStart={(e) => handlePlaneStart(e, plane.id, pos)} onClick={(e) => { e.stopPropagation(); }} className="absolute cursor-pointer group pointer-events-auto" style={{ left: pos.x, top: pos.y }}>
                    <div className="absolute w-12 h-12 -translate-x-1/2 -translate-y-1/2 bg-transparent z-10" />
                    {plane.tutorialHint && score < 10 && (
                        <div className="absolute -top-16 left-8 bg-blue-600 text-white text-[12px] font-bold px-3 py-2 rounded shadow-xl whitespace-nowrap z-50 animate-bounce border-2 border-white">{plane.tutorialHint}<div className="absolute top-full left-0 w-0 h-0 border-t-[8px] border-t-white border-r-[8px] border-r-transparent"></div></div>
                    )}
                    <div className={`absolute w-1.5 h-1.5 -translate-x-1/2 -translate-y-1/2 rounded-sm z-20 ${hasSquawk7700 ? 'bg-red-500 animate-ping' : plane.squawk === '7600' ? 'bg-orange-500' : isEmergency ? 'bg-red-500 animate-pulse' : 'bg-emerald-400'}`} />
                    {isWarning && (<div className="absolute w-12 h-12 -translate-x-1/2 -translate-y-1/2 border border-orange-500 rounded-full animate-pulse opacity-80 z-10 shadow-[0_0_10px_rgba(249,115,22,0.6)]" />)}
                    {isEmergency && (<div className="absolute w-16 h-16 -translate-x-1/2 -translate-y-1/2 border-2 border-red-600 rounded-full animate-ping opacity-100 z-10" />)}
                    {isSelected && (<><div className="absolute w-6 h-6 -translate-x-1/2 -translate-y-1/2 border border-emerald-300 opacity-80 z-10" /><div className="absolute w-10 h-10 -translate-x-1/2 -translate-y-1/2 border border-yellow-400 rounded-full opacity-100 z-10 animate-pulse shadow-[0_0_10px_rgba(250,204,21,0.5)]" /></>)}
                    <div className={`absolute top-0 left-0 h-[1px] origin-left pointer-events-none ${isSelected ? 'w-[80px] bg-white opacity-80' : 'w-[40px] bg-emerald-500/50'}`} style={{ transform: `rotate(${plane.heading - 90}deg)` }} />
                    <div className={`absolute left-3 -top-4 text-[11px] font-mono leading-none whitespace-nowrap pointer-events-none select-none z-30 ${isEmergency || hasSquawk7700 ? 'text-red-500 font-bold' : isWarning ? 'text-orange-400 font-bold' : 'text-[#4ade80] drop-shadow-[0_1px_1px_rgba(0,0,0,0.8)]'}`}>
                        <div className="font-bold mb-0.5">{plane.callsign}</div>
                        <div className="flex gap-2"><span>{Math.floor(plane.altitude / 100).toString().padStart(3,'0')}{plane.targetAltitude !== plane.altitude && (<span className="text-[9px] align-top text-emerald-200">{plane.targetAltitude > plane.altitude ? '↑' : '↓'}</span>)}</span><span>{Math.floor(plane.speed / 10).toString().padStart(2,'0')}</span></div>
                        <div className={`font-bold ${isEmergency || hasSquawk7700 ? 'text-red-500' : isWarning ? 'text-orange-400' : navColor}`}>{navLabel}</div>
                    </div>
                </div>
              </React.Fragment>
            );
          })}
      </div>

      <div className="absolute rounded-full pointer-events-none z-20" style={{ width: radarPixelRadius * 2, height: radarPixelRadius * 2, left: centerPos.x - radarPixelRadius, top: centerPos.y - radarPixelRadius, background: 'radial-gradient(circle, rgba(16,185,129,0) 0%, rgba(16,185,129,0.0) 40%, rgba(16,185,129,0.05) 60%, rgba(16,185,129,0) 70%)' }}>
           <div className="absolute top-1/2 left-1/2 w-1/2 h-[2px] bg-gradient-to-r from-transparent via-emerald-500/20 to-emerald-500/80 origin-left" style={{ transform: `translate(0, -50%) rotate(${sweepAngle - 90}deg)`, boxShadow: "0 0 15px 1px rgba(16, 185, 129, 0.4)" }} />
      </div>
    </div>
  );
};
export default RadarScreen;

import React, { useState, useRef, useEffect } from 'react';
import { Aircraft, RadioMessage, Airport, PendingUpdates } from '../types';

interface ControlPanelProps {
  aircraft: Aircraft | null;
  airport: Airport | null;
  pendingUpdates: PendingUpdates; // Received from parent
  setPendingUpdates: (updates: PendingUpdates) => void; // Update parent
  radioHistory: RadioMessage[];
  onSendCommand: (text: string) => void;
  isProcessingRadio: boolean;
  // Voice Settings
  availableVoices: SpeechSynthesisVoice[];
  currentVoiceURI: string | null;
  onVoiceChange: (voiceURI: string) => void;
  onPlayTransmitSound?: () => void;
}

// Mapeo de códigos ICAO a fraseología de radio
const AIRLINE_NAMES: Record<string, string> = {
  'AMX': 'Aeroméxico',
  'VOI': 'Volaris',
  'VIV': 'Viva Aerobus',
  'DAL': 'Delta',
  'UAL': 'United',
  'AAL': 'American',
  'CMP': 'Copa',
  'AVA': 'Avianca',
  'IBE': 'Iberia',
  'LRC': 'Lacsa',
  'KLM': 'KLM',
  'AFR': 'Air France',
  'DLH': 'Lufthansa',
  'JBU': 'JetBlue',
  'SLI': 'Costera',
  'GMT': 'Magnicharters',
  'TAO': 'Aeromar'
};

const getSpokenCallsign = (callsign: string) => {
  const code = callsign.substring(0, 3).toUpperCase();
  const number = callsign.substring(3);
  const name = AIRLINE_NAMES[code] || code.split('').join(' '); 
  return `${name} ${number}`;
};

const ControlPanel: React.FC<ControlPanelProps> = ({ 
  aircraft, 
  airport,
  pendingUpdates,
  setPendingUpdates,
  radioHistory, 
  onSendCommand,
  isProcessingRadio,
  availableVoices,
  currentVoiceURI,
  onVoiceChange,
  onPlayTransmitSound
}) => {
  const [inputText, setInputText] = useState('');
  const [isListening, setIsListening] = useState(false);
  const [showWaypoints, setShowWaypoints] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const chatEndRef = useRef<HTMLDivElement>(null);

  // Mobile Tabs State
  const [activeTab, setActiveTab] = useState<'controls' | 'radio'>('controls');
  const [unreadCount, setUnreadCount] = useState(0);

  useEffect(() => {
    // Only scroll if we are near bottom or it's a new message
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });

    // Increment unread count if we are not on the radio tab
    if (activeTab !== 'radio' && radioHistory.length > 0) {
        setUnreadCount(prev => prev + 1);
    }
  }, [radioHistory]);

  // Reset count when switching to radio
  useEffect(() => {
    if (activeTab === 'radio') {
        setUnreadCount(0);
    }
  }, [activeTab]);

  // Determine if there are unsent changes
  const hasChanges = aircraft && (
    (pendingUpdates.heading !== null && pendingUpdates.heading !== Math.round(aircraft.targetHeading)) ||
    (pendingUpdates.altitude !== null && pendingUpdates.altitude !== Math.round(aircraft.targetAltitude)) ||
    (pendingUpdates.speed !== null && pendingUpdates.speed !== Math.round(aircraft.targetSpeed)) ||
    (pendingUpdates.clearedForILS !== aircraft.clearedForILS) ||
    (pendingUpdates.directTo !== null)
  );

  const handleAltitudeChange = (delta: number) => {
    if (!aircraft) return;
    const currentPending = pendingUpdates.altitude ?? Math.round(aircraft.targetAltitude);
    const newAlt = Math.max(0, Math.min(40000, currentPending + delta));

    setPendingUpdates({
        ...pendingUpdates,
        altitude: newAlt,
        clearedForILS: false // Disarm ILS if manually changing altitude
    });
  };

  const handleSpeedChange = (delta: number) => {
    if (!aircraft) return;
    const currentPending = pendingUpdates.speed ?? Math.round(aircraft.targetSpeed);
    const newSpd = Math.max(100, Math.min(600, currentPending + delta));

    setPendingUpdates({
        ...pendingUpdates,
        speed: newSpd
    });
  };

  const handleHeadingChange = (delta: number) => {
    if (!aircraft) return;
    const currentPending = pendingUpdates.heading ?? Math.round(aircraft.targetHeading);
    let newHdg = (currentPending + delta) % 360;
    if (newHdg < 0) newHdg += 360;

    setPendingUpdates({
        ...pendingUpdates,
        heading: newHdg,
        directTo: null, // Cancel direct to if manual heading
        clearedForILS: false // Disarm ILS if manually changing heading
    });
  };

  const handleDirectToSelect = (wpName: string) => {
    setPendingUpdates({
        ...pendingUpdates,
        directTo: wpName,
        clearedForILS: false
    });
    setShowWaypoints(false);
  };

  const toggleILS = () => {
    if (!aircraft) return;
    setPendingUpdates({
        ...pendingUpdates,
        clearedForILS: !pendingUpdates.clearedForILS
    });
  };

  const handleTransmit = () => {
    if (!aircraft || !hasChanges) return;

    // Build the command string based on changes
    const parts = [];

    // Heading / Navigation
    if (pendingUpdates.directTo) {
        parts.push(`directo a ${pendingUpdates.directTo}`);
    } else if (pendingUpdates.heading !== null && pendingUpdates.heading !== Math.round(aircraft.targetHeading)) {
        // Determine turn direction for realism
        let diff = pendingUpdates.heading - aircraft.heading;
        if (diff < -180) diff += 360;
        if (diff > 180) diff -= 360;
        const direction = diff > 0 ? "derecha" : "izquierda";
        parts.push(`vire ${direction} rumbo ${pendingUpdates.heading}`);
    }

    // Altitude
    if (pendingUpdates.altitude !== null && pendingUpdates.altitude !== Math.round(aircraft.targetAltitude)) {
        if (pendingUpdates.altitude > aircraft.altitude) parts.push(`ascienda nivel ${pendingUpdates.altitude}`);
        else parts.push(`descienda nivel ${pendingUpdates.altitude}`);
    }

    // Speed
    if (pendingUpdates.speed !== null && pendingUpdates.speed !== Math.round(aircraft.targetSpeed)) {
        parts.push(`reduzca velocidad a ${pendingUpdates.speed} nudos`);
    }

    // ILS
    if (pendingUpdates.clearedForILS !== aircraft.clearedForILS) {
        if (pendingUpdates.clearedForILS) parts.push(`autorizado para aterrizar ILS pista ${airport?.runwayName || 'activa'}`);
        else parts.push(`cancele aproximación ILS`);
    }

    if (parts.length === 0) return;

    const spokenCallsign = getSpokenCallsign(aircraft.callsign);
    const commandText = `${spokenCallsign}, ${parts.join(', ')}`;

    onPlayTransmitSound?.(); // Play sound effect
    onSendCommand(commandText);
  };

  const handleSubmitText = (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputText.trim() || !aircraft) return;

    let finalMsg = inputText;
    const spokenCallsign = getSpokenCallsign(aircraft.callsign);
    const rawCallsign = aircraft.callsign;

    const lowerInput = finalMsg.toLowerCase();
    if (!lowerInput.startsWith(spokenCallsign.toLowerCase()) && 
        !lowerInput.startsWith(rawCallsign.toLowerCase())) {
        finalMsg = `${spokenCallsign}, ${finalMsg}`;
    }

    onPlayTransmitSound?.(); // Play sound effect
    onSendCommand(finalMsg);
    setInputText('');
  };

  const toggleMic = () => {
    if (isListening) return;
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) {
      alert("Tu navegador no soporta reconocimiento de voz nativo.");
      return;
    }
    const recognition = new SpeechRecognition();
    recognition.lang = 'es-MX';
    recognition.start();
    setIsListening(true);
    recognition.onresult = (event: any) => setInputText(event.results[0][0].transcript);
    recognition.onend = () => setIsListening(false);
  };

  if (!aircraft) {
    return (
      <div className="h-full flex items-center justify-center text-slate-500 font-mono text-sm uppercase tracking-widest border-t border-slate-700 bg-slate-900">
        Seleccione una aeronave
      </div>
    );
  }

  // Display values (Pending takes precedence over actual target)
  const displayHeading = pendingUpdates.heading ?? Math.round(aircraft.targetHeading);
  const displayAltitude = pendingUpdates.altitude ?? Math.round(aircraft.targetAltitude);
  const displaySpeed = pendingUpdates.speed ?? Math.round(aircraft.targetSpeed);

  return (
    <div className="h-full bg-slate-900 border-t border-slate-700 p-2 font-mono text-slate-200 grid grid-cols-1 lg:grid-cols-3 gap-2 flex flex-col lg:grid overflow-hidden">

      {/* MOBILE TABS (Visible only on small screens) */}
      <div className="flex lg:hidden gap-1 mb-1 shrink-0">
          <button 
            onClick={() => setActiveTab('controls')}
            className={`flex-1 py-1 text-xs font-bold rounded uppercase border ${activeTab === 'controls' ? 'bg-slate-700 border-slate-500 text-white' : 'bg-slate-900 border-slate-800 text-slate-500'}`}
          >
              Controles
          </button>
          <button 
            onClick={() => setActiveTab('radio')}
            className={`flex-1 py-1 text-xs font-bold rounded uppercase border relative ${activeTab === 'radio' ? 'bg-slate-700 border-slate-500 text-white' : 'bg-slate-900 border-slate-800 text-slate-500'}`}
          >
              Radio
              {unreadCount > 0 && (
                  <span className="absolute -top-1 -right-1 w-3 h-3 bg-red-500 rounded-full animate-ping"></span>
              )}
              {unreadCount > 0 && (
                  <span className="absolute -top-1 -right-1 w-3 h-3 bg-red-500 rounded-full flex items-center justify-center text-[8px] text-white">
                      {unreadCount}
                  </span>
              )}
          </button>
      </div>

      {/* LEFT: Physical Controls */}
      <div className={`lg:col-span-2 grid-cols-3 gap-2 bg-slate-800/50 p-2 rounded border border-slate-700 relative 
        ${activeTab === 'controls' ? 'grid' : 'hidden'} lg:grid overflow-y-auto`}
      >

        {/* Info Header */}
        <div className="col-span-3 flex justify-between items-center border-b border-slate-700 pb-2 mb-2">
            <div>
                <span className="text-xl font-bold text-yellow-400 mr-2">{aircraft.callsign}</span>
                <span className="text-xs text-slate-400">{aircraft.model}</span>
                {aircraft.establishedOnILS && <span className="ml-2 px-2 py-0.5 bg-cyan-900 text-cyan-300 text-[10px] rounded border border-cyan-700">LOC CAPTURED</span>}
            </div>
            <div className="text-xs text-slate-300 flex gap-4">
                <span className="text-slate-400">ACTUAL:</span>
                <span>HDG: {Math.floor(aircraft.heading)}°</span>
                <span>ALT: {Math.floor(aircraft.altitude)}</span>
                <span>SPD: {Math.floor(aircraft.speed)}</span>
            </div>
        </div>

        {/* Heading Control */}
        <div className="flex flex-col items-center border-r border-slate-700 px-2 relative">
          <label className="text-[10px] text-slate-400 mb-1">RUMBO (HDG)</label>
          <div className="flex items-center gap-1">
            <button onClick={() => handleHeadingChange(-10)} className="bg-slate-700 hover:bg-slate-600 p-1 rounded min-w-[30px] text-xs">-10</button>
            <div className={`text-lg font-bold w-16 text-center transition-colors 
                ${pendingUpdates.directTo ? 'text-sky-400 text-xs' : displayHeading !== Math.round(aircraft.targetHeading) ? 'text-yellow-400 animate-pulse' : 'text-emerald-400'}`}>
                {pendingUpdates.directTo ? pendingUpdates.directTo : pendingUpdates.clearedForILS && aircraft.establishedOnILS ? 'ILS' : displayHeading + '°'}
            </div>
            <button onClick={() => handleHeadingChange(10)} className="bg-slate-700 hover:bg-slate-600 p-1 rounded min-w-[30px] text-xs">+10</button>
          </div>
          <div className="flex gap-1 mt-1">
              <button onClick={() => setShowWaypoints(!showWaypoints)} className="text-[9px] bg-sky-800 text-sky-200 px-2 py-0.5 rounded border border-sky-600 hover:bg-sky-700">DIRECTO</button>
          </div>

          {showWaypoints && airport && (
              <div className="absolute bottom-full left-0 w-full bg-slate-800 border border-slate-600 rounded shadow-xl max-h-48 overflow-y-auto z-50">
                  {airport.waypoints.map(wp => (
                      <button 
                        key={wp.name} 
                        onClick={() => handleDirectToSelect(wp.name)}
                        className="w-full text-left px-2 py-1 text-xs hover:bg-slate-700 border-b border-slate-700/50 flex justify-between"
                      >
                          <span className="font-bold text-sky-400">{wp.name}</span>
                          <span className="text-[8px] text-slate-500">{wp.type}</span>
                      </button>
                  ))}
              </div>
          )}
        </div>

        {/* Altitude Control */}
        <div className="flex flex-col items-center border-r border-slate-700 px-2">
          <label className="text-[10px] text-slate-400 mb-1">ALTITUD</label>
          <div className="flex items-center gap-1">
            <button onClick={() => handleAltitudeChange(-1000)} className="bg-slate-700 hover:bg-slate-600 p-1 rounded min-w-[30px] text-xs">-1k</button>
            <div className={`text-lg font-bold w-16 text-center transition-colors
                ${displayAltitude !== Math.round(aircraft.targetAltitude) ? 'text-yellow-400 animate-pulse' : 'text-emerald-400'}`}>
                {pendingUpdates.clearedForILS && aircraft.establishedOnILS ? 'GS' : displayAltitude}
            </div>
            <button onClick={() => handleAltitudeChange(1000)} className="bg-slate-700 hover:bg-slate-600 p-1 rounded min-w-[30px] text-xs">+1k</button>
          </div>
          <button onClick={() => handleAltitudeChange(-100)} className="mt-1 text-[9px] bg-slate-800 px-2 py-0.5 rounded border border-slate-600">Ajuste Fino (-100)</button>
        </div>

        {/* Speed / ILS Control */}
        <div className="flex flex-col items-center px-2">
          <label className="text-[10px] text-slate-400 mb-1">VELOCIDAD</label>
          <div className="flex items-center gap-1">
            <button onClick={() => handleSpeedChange(-20)} className="bg-slate-700 hover:bg-slate-600 p-1 rounded min-w-[30px] text-xs">-20</button>
            <div className={`text-lg font-bold w-12 text-center transition-colors
                ${displaySpeed !== Math.round(aircraft.targetSpeed) ? 'text-yellow-400 animate-pulse' : 'text-emerald-400'}`}>
                {displaySpeed}
            </div>
            <button onClick={() => handleSpeedChange(20)} className="bg-slate-700 hover:bg-slate-600 p-1 rounded min-w-[30px] text-xs">+20</button>
          </div>

          <button 
                onClick={toggleILS}
                className={`mt-2 w-full text-[10px] px-2 py-1 rounded font-bold uppercase border transition-all ${
                    aircraft.establishedOnILS 
                    ? 'bg-cyan-600 text-white border-cyan-400 shadow-[0_0_10px_rgba(6,182,212,0.5)]'
                    : pendingUpdates.clearedForILS
                        ? 'bg-yellow-600 text-white border-yellow-400 animate-pulse'
                        : 'bg-slate-700 text-slate-400 border-slate-600 hover:bg-slate-600'
                }`}
            >
                {aircraft.establishedOnILS ? 'ILS LOCKED' : pendingUpdates.clearedForILS ? 'ILS ARMADO' : 'ILS APP'}
          </button>
        </div>

        {/* Transmit Button Overlay/Section */}
        <div className="col-span-3 mt-1 flex justify-end">
            <button 
                onClick={handleTransmit}
                disabled={!hasChanges || isProcessingRadio}
                className={`w-full py-2 rounded font-bold tracking-widest transition-all
                    ${!hasChanges 
                        ? 'bg-slate-800 text-slate-600 border border-slate-700 cursor-not-allowed' 
                        : isProcessingRadio
                            ? 'bg-emerald-900 text-emerald-500 border border-emerald-700 animate-pulse cursor-wait'
                            : 'bg-emerald-600 text-white hover:bg-emerald-500 border border-emerald-400 shadow-[0_0_15px_rgba(16,185,129,0.4)]'
                    }`}
            >
                {isProcessingRadio ? 'TRANSMITIENDO...' : hasChanges ? 'TRANSMITIR COMANDOS' : 'TRANSMITIR COMANDOS'}
            </button>
        </div>
      </div>

      {/* RIGHT: Radio / Communication */}
      <div className={`flex flex-col bg-black rounded border border-slate-700 overflow-hidden relative lg:flex lg:h-full 
        ${activeTab === 'radio' ? 'flex-1 h-full' : 'hidden'}`}
      >
        {/* Header */}
        <div className="bg-slate-800 px-2 py-1 text-[10px] font-bold text-slate-400 flex justify-between items-center shrink-0">
            <span>FRECUENCIA 118.1</span>
            <div className="flex gap-2">
                 {isProcessingRadio && <span className="text-emerald-400 animate-pulse">TX...</span>}
                 <button onClick={() => setShowSettings(!showSettings)} className="hover:text-white" title="Configuración de Voz">
                    ⚙️
                 </button>
            </div>
        </div>

        {/* Voice Settings Popover */}
        {showSettings && (
            <div className="absolute top-7 right-2 left-2 z-50 bg-slate-800 border border-slate-600 rounded shadow-xl p-2 text-xs">
                <div className="flex justify-between items-center mb-1">
                    <span className="font-bold text-slate-300">Voz ATC / Sistema</span>
                    <button onClick={() => setShowSettings(false)} className="text-slate-500 hover:text-white">✕</button>
                </div>
                <select 
                    value={currentVoiceURI || ''}
                    onChange={(e) => onVoiceChange(e.target.value)}
                    className="w-full bg-black border border-slate-600 rounded p-1 text-slate-200 focus:outline-none"
                >
                    {availableVoices.length === 0 && <option value="">Por defecto (Sistema)</option>}
                    {availableVoices.map(v => (
                        <option key={v.voiceURI} value={v.voiceURI}>
                            {v.name} ({v.lang})
                        </option>
                    ))}
                </select>
                <div className="mt-2 text-[10px] text-slate-500 italic">
                    * Los pilotos tendrán voces aleatorias.
                </div>
            </div>
        )}

        {/* Messages Log (Scrollable, takes remaining space) */}
        <div className="flex-1 overflow-y-auto p-2 space-y-2 text-xs font-mono min-h-0 bg-black/50">
          {radioHistory.length === 0 && (
            <div className="text-slate-600 italic text-center mt-4">Canal libre.</div>
          )}
          {radioHistory.map((msg) => (
            <div key={msg.id} className={`flex flex-col ${msg.sender === 'ATC' ? 'items-end' : 'items-start'}`}>
              <div className={`px-2 py-1 rounded max-w-[90%] ${
                msg.sender === 'ATC' ? 'bg-sky-900/40 text-sky-200 border border-sky-800' : 'bg-emerald-900/40 text-emerald-200 border border-emerald-800'
              }`}>
                <span className="font-bold mr-1 text-[10px] opacity-70 block">
                  {msg.sender === 'ATC' ? 'TWR' : msg.callsign}:
                </span>
                {msg.text}
              </div>
            </div>
          ))}
          <div ref={chatEndRef} />
        </div>

        {/* Input Area (Static at bottom) */}
        <form onSubmit={handleSubmitText} className="p-1 bg-slate-900 border-t border-slate-800 flex gap-1 shrink-0 z-10 relative">
          <button 
            type="button" 
            onClick={toggleMic}
            className={`p-2 rounded transition-colors ${isListening ? 'bg-red-600 text-white animate-pulse' : 'bg-slate-800 text-slate-400 hover:text-white'}`}
          >
            <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" className="w-4 h-4">
              <path d="M8.25 4.5a3.75 3.75 0 117.5 0v8.25a3.75 3.75 0 11-7.5 0V4.5z" />
              <path d="M6 10.5a.75.75 0 01.75.75v1.5a5.25 5.25 0 1010.5 0v-1.5a.75.75 0 011.5 0v1.5a6.751 6.751 0 01-6 6.709v2.291h3a.75.75 0 010 1.5h-7.5a.75.75 0 010-1.5h3v-2.291a6.751 6.751 0 01-6-6.709v-1.5A.75.75 0 016 10.5z" />
            </svg>
          </button>
          <input 
            type="text" 
            value={inputText}
            onChange={(e) => setInputText(e.target.value)}
            className="flex-1 bg-black border border-slate-700 rounded px-2 text-sm text-green-400 font-mono focus:outline-none focus:border-green-500 placeholder-slate-700"
            placeholder="Instrucciones manuales..." 
            disabled={isProcessingRadio}
          />
          <button 
            type="submit" 
            className="bg-emerald-700 hover:bg-emerald-600 text-white px-3 py-1 rounded text-xs font-bold transition-colors disabled:opacity-50"
            disabled={isProcessingRadio || !inputText.trim()}
          >
            ENV
          </button>
        </form>
      </div>
    </div>
  );
};

export default ControlPanel;

import React, { useEffect, useState, useRef } from 'react';
import { Aircraft, Airport, FlightStatus, PendingUpdates, Coordinates } from '../types';

interface RadarScreenProps {
  aircraft: Aircraft[];
  airport: Airport;
  selectedAircraftId: string | null;
  onSelectAircraft: (id: string | null) => void;
  pendingUpdates: PendingUpdates | null;
  onRadarInteraction: (updates: { heading?: number | null, directTo?: string | null }) => void;
  weatherSeverity: number; 
  score: number; 
  gameTier: number; // For alternates
  ashCloud?: { points: Coordinates[], maxAltitude: number } | null;
}

const TURN_RATE_PER_TICK = 0.60; 
const SIM_SPEED_FACTOR = 1.0; 

const RadarScreen: React.FC<RadarScreenProps> = ({ 
  aircraft, 
  airport, 
  selectedAircraftId, 
  onSelectAircraft,
  pendingUpdates,
  onRadarInteraction,
  weatherSeverity,
  score,
  gameTier,
  ashCloud
}) => {
  const [sweepAngle, setSweepAngle] = useState(0);
  const [mapOpacity, setMapOpacity] = useState(0.4);
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const mapInstanceRef = useRef<any>(null);
  const tileLayerRef = useRef<any>(null); 
  const weatherLayerRef = useRef<any>(null); 
  const markersRef = useRef<{[key: string]: any}>({}); 
  const ilsLayerRef = useRef<any>(null); 
  const captureZoneLayerRef = useRef<any>(null); 
  const coverageLayerRef = useRef<any>(null); 
  const ashLayerRef = useRef<any>(null);
  const alternateLayerRef = useRef<any>(null);
  const [projectionVersion, setProjectionVersion] = useState(0); 
  const [radarPixelRadius, setRadarPixelRadius] = useState(600); 

  const [isDragging, setIsDragging] = useState(false);
  const [dragStartPos, setDragStartPos] = useState<{x: number, y: number} | null>(null);
  const [dragCurrentPos, setDragCurrentPos] = useState<{x: number, y: number} | null>(null);
  const [dragHeading, setDragHeading] = useState<number | null>(null);
  const [snappedWaypoint, setSnappedWaypoint] = useState<string | null>(null);

  const selectedPlane = aircraft.find(p => p.id === selectedAircraftId);
  const isSelectedPlaneEstablished = selectedPlane?.establishedOnILS;

  // Fix Map Rendering Issues (Tiles not loading)
  useEffect(() => {
      const handleResize = () => {
          if (mapInstanceRef.current) {
              mapInstanceRef.current.invalidateSize();
          }
      };
      window.addEventListener('resize', handleResize);
      // Force update on mount after layout settlement
      const timer = setTimeout(() => handleResize(), 500);
      return () => {
          window.removeEventListener('resize', handleResize);
          clearTimeout(timer);
      };
  }, []);

  useEffect(() => {
    if (!mapContainerRef.current) return;
    if (!mapInstanceRef.current) {
        // @ts-ignore
        const map = window.L.map(mapContainerRef.current, {
            center: [airport.location.lat, airport.location.lon],
            zoom: airport.initialZoom,
            zoomControl: false,
            attributionControl: false,
            boxZoom: false,
            doubleClickZoom: false,
            dragging: true,
            scrollWheelZoom: true,
            touchZoom: true,
            minZoom: 5, // Expanded range
            maxZoom: 18 // Expanded range
        });

        // @ts-ignore
        const tileLayer = window.L.tileLayer('https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png', {
            attribution: '&copy; OpenStreetMap &copy; CARTO',
            subdomains: 'abcd',
            maxZoom: 20,
            opacity: mapOpacity 
        }).addTo(map);

        mapInstanceRef.current = map;
        tileLayerRef.current = tileLayer;

        map.on('move', () => setProjectionVersion(v => v + 1));
        map.on('zoom', () => setProjectionVersion(v => v + 1));
        map.on('click', () => { onSelectAircraft(null); });

        // Initial invalidate to ensure tiles load correctly
        setTimeout(() => map.invalidateSize(), 200);

    } else {
        mapInstanceRef.current.setView([airport.location.lat, airport.location.lon], airport.initialZoom);
    }
  }, [airport, onSelectAircraft]);

  useEffect(() => {
      if (!mapInstanceRef.current) return;
      const fetchWeather = async () => {
          try {
              const response = await fetch('https://api.rainviewer.com/public/weather-maps.json');
              const data = await response.json();
              if (data && data.radar && data.radar.past && data.radar.past.length > 0) {
                  const lastPast = data.radar.past[data.radar.past.length - 1];
                  const time = lastPast.time;
                  const host = data.host; 
                  const url = `${host}${time}/256/{z}/{x}/{y}/2/1_1.png`;
                  if (weatherLayerRef.current) weatherLayerRef.current.remove();
                  // @ts-ignore
                  weatherLayerRef.current = window.L.tileLayer(url, { opacity: 0, zIndex: 10 }).addTo(mapInstanceRef.current);
              }
          } catch (e) { console.warn("RainViewer failed", e); }
      };
      fetchWeather();
      const interval = setInterval(fetchWeather, 600000);
      return () => clearInterval(interval);
  }, []);

  useEffect(() => {
      if (weatherLayerRef.current) weatherLayerRef.current.setOpacity(weatherSeverity * 0.6);
  }, [weatherSeverity]);

  useEffect(() => {
    if (!mapInstanceRef.current) return;
    const map = mapInstanceRef.current;
    const updateRadarSize = () => {
        const centerLatLng = [airport.location.lat, airport.location.lon];
        const edgeLatLng = [airport.location.lat + 1.8, airport.location.lon]; 
        // @ts-ignore
        const p1 = map.latLngToContainerPoint(centerLatLng);
        // @ts-ignore
        const p2 = map.latLngToContainerPoint(edgeLatLng);
        setRadarPixelRadius(Math.abs(p1.y - p2.y));
    };
    updateRadarSize();
    map.on('zoomend', updateRadarSize);
    return () => { map.off('zoomend', updateRadarSize); };
  }, [airport, projectionVersion]); 

  useEffect(() => {
    if (!mapInstanceRef.current) return;
    if (coverageLayerRef.current) coverageLayerRef.current.remove();
    // @ts-ignore
    coverageLayerRef.current = window.L.circle([airport.location.lat, airport.location.lon], {
        radius: 200000,
        color: '#475569', 
        weight: 1,
        dashArray: '4, 8',
        fill: false,
        opacity: 0.5,
        interactive: false
    }).addTo(mapInstanceRef.current);

    // Add Volcano Marker for Popocatepetl if MMMX
    if (airport.code === 'MMMX') {
         // @ts-ignore
         window.L.marker([19.0228, -98.6278], {
             // @ts-ignore
             icon: window.L.divIcon({
                 className: 'bg-transparent',
                 html: '<div class="text-xl">🌋</div>',
                 iconSize: [20, 20]
             })
         }).addTo(mapInstanceRef.current);
    }

    return () => { if (coverageLayerRef.current) coverageLayerRef.current.remove(); };
  }, [airport]);

  // Ash Cloud Rendering
  useEffect(() => {
      if (!mapInstanceRef.current) return;
      if (ashLayerRef.current) ashLayerRef.current.remove();

      if (ashCloud) {
          const latlngs = ashCloud.points.map(p => [p.lat, p.lon]);
          // @ts-ignore
          ashLayerRef.current = window.L.polygon(latlngs, {
              color: '#71717a', // Zinc 500
              fillColor: '#52525b', // Zinc 600
              fillOpacity: 0.4,
              weight: 0,
              className: 'animate-pulse'
          }).addTo(mapInstanceRef.current);
      }
      return () => { if (ashLayerRef.current) ashLayerRef.current.remove(); };
  }, [ashCloud]);

  // Alternate Airports (Level 1+)
  useEffect(() => {
      if (!mapInstanceRef.current) return;
      if (alternateLayerRef.current) alternateLayerRef.current.clearLayers();
      else // @ts-ignore 
           alternateLayerRef.current = window.L.layerGroup().addTo(mapInstanceRef.current);

      if (gameTier >= 1 && airport.alternates) {
           airport.alternates.forEach(alt => {
               // Marker
               // @ts-ignore
               window.L.marker([alt.location.lat, alt.location.lon], {
                   // @ts-ignore
                   icon: window.L.divIcon({
                       className: 'bg-transparent',
                       html: `<div class="w-2 h-2 bg-slate-400 border border-slate-200"></div><div class="text-[9px] text-slate-400 font-mono mt-1">${alt.code}</div>`,
                       iconSize: [30, 30]
                   })
               }).addTo(alternateLayerRef.current);

               // ILS Line for alternate
               const localizerAngle = (alt.runwayHeading + 180) % 360;
               const endLat = alt.location.lat + (alt.ilsLengthNM / 60) * Math.cos(localizerAngle * Math.PI / 180);
               const endLon = alt.location.lon + (alt.ilsLengthNM / 60) * Math.sin(localizerAngle * Math.PI / 180) / Math.cos(alt.location.lat * Math.PI / 180);

               // @ts-ignore
               window.L.polyline([[alt.location.lat, alt.location.lon], [endLat, endLon]], {
                   color: '#3b82f6',
                   weight: 2,
                   opacity: 0.5,
                   dashArray: '5,5'
               }).addTo(alternateLayerRef.current);
           });
      }
  }, [gameTier, airport]);

  useEffect(() => {
    if (tileLayerRef.current) tileLayerRef.current.setOpacity(mapOpacity);
  }, [mapOpacity]);

  useEffect(() => {
    if (!mapInstanceRef.current) return;
    const map = mapInstanceRef.current;
    Object.values(markersRef.current).forEach((marker: any) => map.removeLayer(marker));
    markersRef.current = {};
    airport.waypoints.forEach(wp => {
        const isSnapped = snappedWaypoint === wp.name || (pendingUpdates?.directTo === wp.name && selectedAircraftId !== null);
        const icon = createWaypointIcon(wp, isSnapped);
        // @ts-ignore
        const marker = window.L.marker([wp.location.lat, wp.location.lon], { icon, interactive: false }).addTo(map);
        markersRef.current[wp.name] = marker;
    });
    return () => { Object.values(markersRef.current).forEach((marker: any) => map.removeLayer(marker)); };
  }, [airport.waypoints]); 

  useEffect(() => {
      airport.waypoints.forEach(wp => {
          const marker = markersRef.current[wp.name];
          if (marker) {
              const isSnapped = snappedWaypoint === wp.name || (pendingUpdates?.directTo === wp.name && selectedAircraftId !== null);
              const newIcon = createWaypointIcon(wp, isSnapped);
              marker.setIcon(newIcon);
          }
      });
  }, [snappedWaypoint, pendingUpdates?.directTo, selectedAircraftId]);

  // --- ILS LINE RENDER (Static per airport) ---
  useEffect(() => {
    if (!mapInstanceRef.current) return;

    // Clean up previous ILS if exists (when airport changes)
    if (ilsLayerRef.current) {
        ilsLayerRef.current.remove();
        ilsLayerRef.current = null;
    }

    const localizerAngle = (airport.runwayHeading + 180) % 360;
    const ILS_LENGTH_NM = 18;
    const projectPoint = (lat: number, lon: number, brng: number, distNM: number) => {
        const R = 3440.065; 
        const d = distNM / R;
        const brngRad = brng * Math.PI / 180;
        const latRad = lat * Math.PI / 180;
        const lonRad = lon * Math.PI / 180;
        const lat2 = Math.asin(Math.sin(latRad) * Math.cos(d) + Math.cos(latRad) * Math.sin(d) * Math.cos(brngRad));
        const lon2 = lonRad + Math.atan2(Math.sin(brngRad) * Math.sin(d) * Math.cos(latRad), Math.cos(d) - Math.sin(latRad) * Math.sin(lat2));
        return [lat2 * 180 / Math.PI, lon2 * 180 / Math.PI];
    };

    const startCoords = [airport.location.lat, airport.location.lon];
    const endCoords = projectPoint(airport.location.lat, airport.location.lon, localizerAngle, ILS_LENGTH_NM);

    // @ts-ignore
    ilsLayerRef.current = window.L.polyline([startCoords, endCoords], {
        weight: 5,
        opacity: 1.0,
        color: '#3b82f6', 
        lineCap: 'butt'
    }).addTo(mapInstanceRef.current);

    return () => {
        if (ilsLayerRef.current) {
            ilsLayerRef.current.remove();
            ilsLayerRef.current = null;
        }
    };
  }, [airport]);

  // --- CAPTURE ZONE RENDER (Dynamic based on score) ---
  useEffect(() => {
    if (!mapInstanceRef.current) return;

    if (!captureZoneLayerRef.current) {
         // @ts-ignore
         captureZoneLayerRef.current = window.L.layerGroup().addTo(mapInstanceRef.current);
    }

    captureZoneLayerRef.current.clearLayers();

    if (score < 10) {
        const localizerAngle = (airport.runwayHeading + 180) % 360;
        const ILS_LENGTH_NM = 18;
        const projectPoint = (lat: number, lon: number, brng: number, distNM: number) => {
            const R = 3440.065; 
            const d = distNM / R;
            const brngRad = brng * Math.PI / 180;
            const latRad = lat * Math.PI / 180;
            const lonRad = lon * Math.PI / 180;
            const lat2 = Math.asin(Math.sin(latRad) * Math.cos(d) + Math.cos(latRad) * Math.sin(d) * Math.cos(brngRad));
            const lon2 = lonRad + Math.atan2(Math.sin(brngRad) * Math.sin(d) * Math.cos(latRad), Math.cos(d) - Math.sin(latRad) * Math.sin(lat2));
            return [lat2 * 180 / Math.PI, lon2 * 180 / Math.PI];
        };

        const startCoords = [airport.location.lat, airport.location.lon];
        const leftLimit = (localizerAngle - 15 + 360) % 360;
        const rightLimit = (localizerAngle + 15) % 360;
        const leftEnd = projectPoint(airport.location.lat, airport.location.lon, leftLimit, ILS_LENGTH_NM - 3);
        const rightEnd = projectPoint(airport.location.lat, airport.location.lon, rightLimit, ILS_LENGTH_NM - 3);

        // @ts-ignore
        window.L.polyline([startCoords, leftEnd], { color: '#fbbf24', dashArray: '10, 10', weight: 2, opacity: 0.6 }).addTo(captureZoneLayerRef.current);
        // @ts-ignore
        window.L.polyline([startCoords, rightEnd], { color: '#fbbf24', dashArray: '10, 10', weight: 2, opacity: 0.6 }).addTo(captureZoneLayerRef.current);
        const labelPos = projectPoint(airport.location.lat, airport.location.lon, localizerAngle, ILS_LENGTH_NM - 5);
        // @ts-ignore
        window.L.marker(labelPos, { icon: window.L.divIcon({ className: 'bg-transparent', html: '<div class="text-[#fbbf24] text-[10px] font-mono opacity-60 -rotate-90 whitespace-nowrap">ZONA DE CAPTURA ILS</div>', iconSize: [100, 20] }) }).addTo(captureZoneLayerRef.current);
    }

    // No return cleanup needed for the group itself, just clearLayers is enough on update
  }, [airport, score]);

  useEffect(() => {
    if (ilsLayerRef.current) {
        if (isSelectedPlaneEstablished) ilsLayerRef.current.setStyle({ color: '#10b981', opacity: 1, weight: 6 });
        else ilsLayerRef.current.setStyle({ color: '#3b82f6', opacity: 1.0, weight: 5 });
    }
  }, [isSelectedPlaneEstablished]);

  const createWaypointIcon = (wp: any, isSnapped: boolean) => {
      // @ts-ignore
      return window.L.divIcon({
          className: 'bg-transparent border-none',
          html: `
            <div class="relative flex flex-col items-center justify-center transition-all duration-200 ${isSnapped ? 'scale-125 z-50' : ''}">
                ${isSnapped ? '<div class="absolute w-12 h-12 rounded-full border-2 border-cyan-400 animate-pulse bg-cyan-900/30 left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2"></div>' : ''}
                ${wp.type === 'VOR' ? 
                    `<svg width="18" height="18" viewBox="0 0 24 24" class="${isSnapped ? 'text-cyan-400' : 'text-slate-400'} stroke-current stroke-[2px] fill-slate-900/50"><path d="M12 2l8.66 5v10L12 22l-8.66-5V7L12 2z" /><circle cx="12" cy="12" r="2" class="fill-current" /></svg>` : 
                 wp.type === 'FIX' ? 
                    `<svg width="10" height="10" viewBox="0 0 24 24" class="${isSnapped ? 'text-cyan-400' : 'text-slate-600'} fill-current opacity-80"><path d="M12 4L4 20h16z" /></svg>` :
                    `<div class="w-4 h-4 border-2 border-slate-300 bg-slate-900/30"></div>`
                }
                <div class="mt-1 text-[10px] font-mono font-bold whitespace-nowrap tracking-wider drop-shadow-md ${isSnapped ? 'text-cyan-300 scale-110' : 'text-slate-400'}">${wp.name}</div>
            </div>
          `,
          iconSize: [40, 40],
          iconAnchor: [20, 20] 
      });
  };

  useEffect(() => {
    const interval = setInterval(() => { setSweepAngle((prev) => (prev + 1.5) % 360); }, 20);
    return () => clearInterval(interval);
  }, []);

  const project = (lat: number, lon: number) => {
      if (!mapInstanceRef.current) return { x: 0, y: 0 };
      // @ts-ignore
      const point = mapInstanceRef.current.latLngToContainerPoint([lat, lon]);
      return { x: point.x, y: point.y };
  };

  useEffect(() => {
      const handleGlobalMove = (e: MouseEvent | TouchEvent) => {
          if (!isDragging || !dragStartPos || !mapContainerRef.current) return;
          let clientX, clientY;
          if ('touches' in e) { clientX = (e as TouchEvent).touches[0].clientX; clientY = (e as TouchEvent).touches[0].clientY; } 
          else { clientX = (e as MouseEvent).clientX; clientY = (e as MouseEvent).clientY; }
          const rect = mapContainerRef.current.getBoundingClientRect();
          const x = clientX - rect.left;
          const y = clientY - rect.top;
          setDragCurrentPos({ x, y });
          let foundSnap = null;
          for (const wp of airport.waypoints) {
              const wpPos = project(wp.location.lat, wp.location.lon);
              const dist = Math.sqrt(Math.pow(x - wpPos.x, 2) + Math.pow(y - wpPos.y, 2));
              if (dist < 40) { foundSnap = wp.name; break; }
          }
          if (foundSnap) {
              setSnappedWaypoint(foundSnap);
              setDragHeading(null);
              onRadarInteraction({ directTo: foundSnap });
          } else {
              setSnappedWaypoint(null);
              const dx = x - dragStartPos.x;
              const dy = y - dragStartPos.y;
              const angleRad = Math.atan2(dy, dx);
              let angleDeg = angleRad * 180 / Math.PI;
              let compassHeading = (angleDeg + 90) % 360;
              if (compassHeading < 0) compassHeading += 360;
              const newHeading = Math.round(compassHeading);
              setDragHeading(newHeading);
              onRadarInteraction({ heading: newHeading });
          }
      };
      const handleGlobalUp = () => {
          if (isDragging) {
              setIsDragging(false);
              setDragStartPos(null);
              setDragCurrentPos(null);
              setDragHeading(null);
              setSnappedWaypoint(null);
          }
      };
      window.addEventListener('mousemove', handleGlobalMove);
      window.addEventListener('mouseup', handleGlobalUp);
      window.addEventListener('touchmove', handleGlobalMove, { passive: false });
      window.addEventListener('touchend', handleGlobalUp);
      return () => {
          window.removeEventListener('mousemove', handleGlobalMove);
          window.removeEventListener('mouseup', handleGlobalUp);
          window.removeEventListener('touchmove', handleGlobalMove);
          window.removeEventListener('touchend', handleGlobalUp);
      }
  }, [isDragging, dragStartPos, onRadarInteraction, airport.waypoints]);

  const centerPos = project(airport.location.lat, airport.location.lon);

  const handlePlaneStart = (e: React.MouseEvent | React.TouchEvent, planeId: string, pos: {x: number, y: number}) => {
      e.stopPropagation(); 
      onSelectAircraft(planeId);
      setIsDragging(true);
      setDragStartPos(pos);
      setDragCurrentPos(pos);
  };

  const calculatePath = (startLat: number, startLon: number, startHdg: number, targetHdg: number, speedKnots: number) => {
    const points: string[] = [];
    let currentLat = startLat;
    let currentLon = startLon;
    let currentHdg = startHdg;
    const tickDurationHours = 0.2 / 3600; 
    let limit = 1500; 
    for (let i = 0; i < limit; i++) {
        if (i % 10 === 0) { const p = project(currentLat, currentLon); points.push(`${p.x},${p.y}`); }
        let diff = targetHdg - currentHdg;
        if (diff < -180) diff += 360;
        if (diff > 180) diff -= 360;
        if (Math.abs(diff) < TURN_RATE_PER_TICK) currentHdg = targetHdg;
        else currentHdg += Math.sign(diff) * TURN_RATE_PER_TICK;
        currentHdg = (currentHdg + 360) % 360;
        const distNM = speedKnots * tickDurationHours * SIM_SPEED_FACTOR;
        const distDeg = distNM / 60;
        const radHdg = currentHdg * Math.PI / 180;
        const dLat = distDeg * Math.cos(radHdg);
        const dLon = distDeg * Math.sin(radHdg) / Math.cos(currentLat * Math.PI / 180);
        currentLat += dLat;
        currentLon += dLon;
        if (currentHdg === targetHdg) {
            const remainingTicks = 4000; 
            const finalDistNM = speedKnots * (remainingTicks * 0.2 / 3600);
            const finalDistDeg = finalDistNM / 60;
            const finalLat = currentLat + finalDistDeg * Math.cos(radHdg);
            const finalLon = currentLon + finalDistDeg * Math.sin(radHdg) / Math.cos(currentLat * Math.PI / 180);
            const pEnd = project(finalLat, finalLon);
            points.push(`${pEnd.x},${pEnd.y}`);
            break;
        }
    }
    return points.join(' ');
  };

  let directToLineCoords = null;
  let curvedPathPoints = null;

  if (selectedPlane) {
      if (pendingUpdates?.directTo) {
        const wp = airport.waypoints.find(w => w.name === pendingUpdates.directTo);
        if (wp) {
            const start = project(selectedPlane.position.lat, selectedPlane.position.lon);
            const end = project(wp.location.lat, wp.location.lon);
            directToLineCoords = { start, end };
        }
      } else if (pendingUpdates?.heading !== null || (isDragging && dragHeading !== null)) {
        const targetH = isDragging && dragHeading !== null ? dragHeading : (pendingUpdates?.heading !== null ? pendingUpdates.heading : null);
        if (targetH !== null && Math.abs(targetH - selectedPlane.heading) > 1) {
            curvedPathPoints = calculatePath(selectedPlane.position.lat, selectedPlane.position.lon, selectedPlane.heading, targetH, selectedPlane.speed);
        }
      }
  }

  return (
    <div className="relative w-full h-full bg-black overflow-hidden shadow-2xl rounded-lg border border-slate-800 cursor-crosshair touch-none">
      <div ref={mapContainerRef} className="absolute inset-0 z-0"></div>

      {/* Selector de Opacidad - Movido a esquina inferior izquierda */}
      <div className="absolute bottom-4 left-4 z-50 flex items-center gap-2 bg-slate-900/80 p-2 rounded border border-slate-700 pointer-events-auto">
        <span className="text-[9px] text-slate-400 font-mono">MAPA</span>
        <input type="range" min="0" max="1" step="0.1" value={mapOpacity} onChange={(e) => setMapOpacity(parseFloat(e.target.value))} className="w-16 h-1 bg-slate-700 rounded-lg appearance-none cursor-pointer" />
      </div>

      <div className="absolute bottom-4 right-4 z-50 flex flex-col gap-1 pointer-events-auto">
        <button className="w-8 h-8 bg-slate-800 text-slate-300 border border-slate-600 rounded hover:bg-slate-700 flex items-center justify-center font-bold" onClick={() => mapInstanceRef.current?.zoomIn()}>+</button>
        <button className="w-8 h-8 bg-slate-800 text-slate-300 border border-slate-600 rounded hover:bg-slate-700 flex items-center justify-center font-bold" onClick={() => mapInstanceRef.current?.zoomOut()}>-</button>
      </div>

      <div className="absolute inset-0 z-25 pointer-events-none overflow-hidden">
          <svg className="w-full h-full">
            {curvedPathPoints && !snappedWaypoint && (
                <polyline points={curvedPathPoints} fill="none" stroke="#facc15" strokeWidth="3" strokeDasharray="8,6" opacity="1" />
            )}
            {directToLineCoords && (
                <line x1={directToLineCoords.start.x} y1={directToLineCoords.start.y} x2={directToLineCoords.end.x} y2={directToLineCoords.end.y} stroke={snappedWaypoint ? "#22d3ee" : "#facc15"} strokeWidth="3" strokeDasharray={snappedWaypoint ? "0" : "8,6"} />
            )}
          </svg>
          {isDragging && dragCurrentPos && (
              <div className={`absolute rounded px-2 py-1 text-xs font-bold font-mono border ${snappedWaypoint ? 'bg-cyan-900/90 text-cyan-400 border-cyan-500' : 'bg-slate-900/80 text-yellow-400 border-yellow-500'}`} style={{ left: dragCurrentPos.x + 15, top: dragCurrentPos.y + 15 }}>{snappedWaypoint ? `DIRECTO A ${snappedWaypoint}` : `${dragHeading}°`}</div>
          )}
      </div>

      <div className="absolute inset-0 z-30 pointer-events-none">
          {aircraft.map((plane) => {
            if (plane.status === FlightStatus.LANDED || plane.status === FlightStatus.CRASHED) return null;
            const pos = project(plane.position.lat, plane.position.lon);
            const isSelected = plane.id === selectedAircraftId;
            const isEmergency = plane.status === FlightStatus.LOST_SEPARATION || plane.proximityAlert === 'CRITICAL';
            const isWarning = plane.proximityAlert === 'WARNING';
            const isOnILS = plane.establishedOnILS;
            const hasSquawk7700 = plane.squawk === '7700';
            let navLabel = null;
            let navColor = "text-emerald-400";

            if (hasSquawk7700) { navLabel = "SQ 7700"; navColor = "text-red-500 animate-pulse"; } 
            else if (plane.squawk === '7600') { navLabel = "SQ 7600"; navColor = "text-orange-500 animate-pulse"; } 
            else if (isSelected && pendingUpdates?.directTo) { navLabel = `→${pendingUpdates.directTo}`; navColor = "text-yellow-400"; } 
            else if (plane.currentDirectTo && !plane.clearedForILS) { navLabel = `→${plane.currentDirectTo}`; navColor = "text-orange-400"; } 
            else if (isOnILS) { navLabel = `LOC LOCK`; navColor = "text-cyan-400"; } 
            else if (plane.clearedForILS) { navLabel = `ILS ARM`; navColor = "text-blue-400"; } 
            else { navLabel = `H ${Math.round(plane.heading).toString().padStart(3,'0')}`; navColor = "text-slate-400"; }

            if (pos.x < -100 || pos.y < -100 || pos.x > window.innerWidth + 100 || pos.y > window.innerHeight + 100) return null;

            return (
              <React.Fragment key={plane.id}>
                {isSelected && plane.history && plane.history.map((histPos, idx) => {
                    const hPos = project(histPos.lat, histPos.lon);
                    return (<div key={idx} className="absolute w-[2px] h-[2px] bg-emerald-500/40 rounded-full pointer-events-none" style={{ left: hPos.x, top: hPos.y }} />);
                })}
                <div onMouseDown={(e) => handlePlaneStart(e, plane.id, pos)} onTouchStart={(e) => handlePlaneStart(e, plane.id, pos)} onClick={(e) => { e.stopPropagation(); }} className="absolute cursor-pointer group pointer-events-auto" style={{ left: pos.x, top: pos.y }}>
                    <div className="absolute w-12 h-12 -translate-x-1/2 -translate-y-1/2 bg-transparent z-10" />
                    {plane.tutorialHint && score < 10 && (
                        <div className="absolute -top-16 left-8 bg-blue-600 text-white text-[12px] font-bold px-3 py-2 rounded shadow-xl whitespace-nowrap z-50 animate-bounce border-2 border-white">{plane.tutorialHint}<div className="absolute top-full left-0 w-0 h-0 border-t-[8px] border-t-white border-r-[8px] border-r-transparent"></div></div>
                    )}
                    <div className={`absolute w-1.5 h-1.5 -translate-x-1/2 -translate-y-1/2 rounded-sm z-20 ${hasSquawk7700 ? 'bg-red-500 animate-ping' : plane.squawk === '7600' ? 'bg-orange-500' : isEmergency ? 'bg-red-500 animate-pulse' : 'bg-emerald-400'}`} />
                    {isWarning && (<div className="absolute w-12 h-12 -translate-x-1/2 -translate-y-1/2 border border-orange-500 rounded-full animate-pulse opacity-80 z-10 shadow-[0_0_10px_rgba(249,115,22,0.6)]" />)}
                    {isEmergency && (<div className="absolute w-16 h-16 -translate-x-1/2 -translate-y-1/2 border-2 border-red-600 rounded-full animate-ping opacity-100 z-10" />)}
                    {isSelected && (<><div className="absolute w-6 h-6 -translate-x-1/2 -translate-y-1/2 border border-emerald-300 opacity-80 z-10" /><div className="absolute w-10 h-10 -translate-x-1/2 -translate-y-1/2 border border-yellow-400 rounded-full opacity-100 z-10 animate-pulse shadow-[0_0_10px_rgba(250,204,21,0.5)]" /></>)}
                    <div className={`absolute top-0 left-0 h-[1px] origin-left pointer-events-none ${isSelected ? 'w-[80px] bg-white opacity-80' : 'w-[40px] bg-emerald-500/50'}`} style={{ transform: `rotate(${plane.heading - 90}deg)` }} />
                    <div className={`absolute left-3 -top-4 text-[11px] font-mono leading-none whitespace-nowrap pointer-events-none select-none z-30 ${isEmergency || hasSquawk7700 ? 'text-red-500 font-bold' : isWarning ? 'text-orange-400 font-bold' : 'text-[#4ade80] drop-shadow-[0_1px_1px_rgba(0,0,0,0.8)]'}`}>
                        <div className="font-bold mb-0.5">{plane.callsign}</div>
                        <div className="flex gap-2"><span>{Math.floor(plane.altitude / 100).toString().padStart(3,'0')}{plane.targetAltitude !== plane.altitude && (<span className="text-[9px] align-top text-emerald-200">{plane.targetAltitude > plane.altitude ? '↑' : '↓'}</span>)}</span><span>{Math.floor(plane.speed / 10).toString().padStart(2,'0')}</span></div>
                        <div className={`font-bold ${isEmergency || hasSquawk7700 ? 'text-red-500' : isWarning ? 'text-orange-400' : navColor}`}>{navLabel}</div>
                    </div>
                </div>
              </React.Fragment>
            );
          })}
      </div>

      <div className="absolute rounded-full pointer-events-none z-20" style={{ width: radarPixelRadius * 2, height: radarPixelRadius * 2, left: centerPos.x - radarPixelRadius, top: centerPos.y - radarPixelRadius, background: 'radial-gradient(circle, rgba(16,185,129,0) 0%, rgba(16,185,129,0.0) 40%, rgba(16,185,129,0.05) 60%, rgba(16,185,129,0) 70%)' }}>
           <div className="absolute top-1/2 left-1/2 w-1/2 h-[2px] bg-gradient-to-r from-transparent via-emerald-500/20 to-emerald-500/80 origin-left" style={{ transform: `translate(0, -50%) rotate(${sweepAngle - 90}deg)`, boxShadow: "0 0 15px 1px rgba(16, 185, 129, 0.4)" }} />
      </div>
    </div>
  );
};
export default RadarScreen;
